// Auto-generated: quiz content for Cours19 — translations can be added per-locale.
// Structural data arrays (DEGREES, MODES, etc.) remain in the component for now.

export interface Question { q: string; opts: string[]; a: number; fb: string; }
export interface Cours19Locale { questions: Question[]; }

const questionsFr: Question[] = [
  // Familles
  { q: "Combien de grandes familles d'instruments compose l'orchestre symphonique ?", opts: ["2 (cordes et cuivres)", "3 (cordes, bois, cuivres)", "4 (cordes, bois, cuivres, percussions)", "5 (+ piano)"], a: 2, fb: "L'orchestre symphonique comprend 4 grandes familles : cordes (violons, altos, violoncelles, contrebasses), bois (flûte, hautbois, clarinette, basson), cuivres (cor, trompette, trombone, tuba), percussions (timbales, caisse claire, cymbales...). On ajoute parfois harpe, piano ou guitare selon l'œuvre." },
  { q: "Quelle famille d'instruments constitue 'l'épine dorsale' de l'orchestre ?", opts: ["Les cuivres", "Les percussions", "Les cordes — plus nombreuses et les plus présentes", "Les bois"], a: 2, fb: "Les cordes forment la fondation de l'orchestre : elles sont de loin les plus nombreuses (un grand orchestre compte 60+ musiciens de cordes sur ~100 musiciens). Leur homogénéité de timbre permet des fondus et crescendos impossibles avec d'autres familles." },
  { q: "Les 'bois' sont ainsi appelés car :", opts: ["Ils jouent des musiques de forêt", "Historiquement fabriqués en bois — bien que flûtes et saxophones modernes soient souvent en métal", "Ils sont toujours joués en forêt", "Ils produisent toujours un son doux"], a: 1, fb: "Les bois (woodwinds) sont nommés d'après leur matériau historique. Aujourd'hui, les flûtes sont généralement en métal (argent, or) et les saxophones également — mais ils restent classés dans les bois par leur mécanisme de production de son (colonne d'air dans un tube)." },

  // Cordes
  { q: "Quelle est la tessiture pratique du violon ?", opts: ["Do2 – Sol4 (registre grave)", "Sol3 – Mi6 environ (registre soprano)", "Do1 – Do5 (grande étendue)", "La3 – La6 (médium)"], a: 1, fb: "Le violon couvre pratiquement Sol3–Mi6 (avec des extensions possibles jusqu'à La7 pour les virtuoses). C'est l'instrument de mélodie soprano par excellence. Il existe en deux pupitres : Violon I (mélodie principale) et Violon II (harmonie haute)." },
  { q: "Quel instrument à cordes a le timbre le plus sombre et intermédiaire ?", opts: ["Le violon", "L'alto (viola)", "Le violoncelle", "La contrebasse"], a: 1, fb: "L'alto (viola) a un timbre sombre, chaud et légèrement nasal — souvent décrit comme le plus 'humain' des cordes. Sa tessiture intermédiaire (Do3–La5 environ) et son timbre caractéristique en font l'instrument de l'harmonie contralto et des contre-mélodies expressives." },
  { q: "Le violoncelle joue principalement quel rôle dans l'orchestre ?", opts: ["Mélodie soprano uniquement", "Mélodie grave et basse chantante — capable de lignes lyriques expressives dans son registre médium", "Accompagnement rythmique uniquement", "Doublure des cuivres"], a: 1, fb: "Le violoncelle est l'un des instruments les plus polyvalents : basse harmonique (Do2–Si2), contrepoint (médium), et mélodie lyrique (Mi3–La5). Sa capacité à chanter dans le registre ténor l'a rendu favori pour les thèmes principaux (Dvorak Concerto, suite de Bach)." },
  { q: "La contrebasse sonne à quelle hauteur par rapport à la notation ?", opts: ["Comme écrite", "Une octave plus bas que notée", "Une quinte plus bas", "Une tierce plus haut"], a: 1, fb: "La contrebasse est un instrument transpositeur à l'octave inférieure : ce qui est noté Do3 sonne Do2 à l'oreille. Cette convention simplifie la lecture des partitions (évite trop de lignes supplémentaires). Son rôle principal est la fondation harmonique des graves." },
  { q: "Le 'pizzicato' pour les cordes désigne :", opts: ["Jouer avec l'archet", "Pincer les cordes avec les doigts — technique percussive, plus courte et sèche que l'archet", "Jouer très doucement", "Jouer en sourdine"], a: 1, fb: "Le pizzicato est le jeu en pinçant les cordes (sans archet). Il produit une attaque brève et sèche — très utilisé dans les accompagnements de danse, les pizzicato jazz (contrebasse) et les effets de couleur orchestrale. Bartók a développé le 'pizzicato snap' (claqué contre la touche)." },
  { q: "L'archet (arco) sur les cordes produit :", opts: ["Un son bref et sec", "Un son continu — le frottement de la mèche sur la corde crée une vibration soutenue", "Un son pincé", "Un son percussif"], a: 1, fb: "L'archet (arco) produit un son continu par frottement de crin de cheval sur la corde. Cette capacité de son tenu distingue les cordes des instruments à sons brefs. Le détaché, le legato, le spiccato et le col legno (avec le bois de l'archet) sont autant de variantes de techniques d'archet." },

  // Bois
  { q: "Quel est le timbre caractéristique de la flûte en registre aigu ?", opts: ["Grave et sombre", "Aérien, lumineux, brillant — souvent utilisé pour les textures éthérées", "Nasal et poignant", "Massif et puissant"], a: 1, fb: "En registre aigu, la flûte est lumineuse et aérienne — idéale pour les textures impressionnistes (Debussy, Prélude à l'après-midi d'un faune commence par un solo de flûte). En grave (pied de flûte), elle est voilée et mystérieuse. C'est l'instrument le plus agile des bois." },
  { q: "Quel instrument à vent est le plus expressif pour les solos lyriques et poignants ?", opts: ["La flûte", "Le hautbois — son timbre nasal et pénétrant le rend inimitable dans les mélodies expressives", "La clarinette", "Le basson"], a: 1, fb: "Le hautbois est l'instrument dont le timbre se rapproche le plus de la voix humaine nasale. Il a une sonorité très distinctive, reconnaissable même mêlée aux cordes. Solos célèbres : Concerto en la mineur d'Albinoni, Second Concerto brandebourgeois de Bach, Symphonie 4 de Brahms." },
  { q: "La clarinette en Sib transpose ses notes à quelle hauteur ?", opts: ["Comme écrite", "Un ton plus bas que notée (do sonne Sib)", "Un ton plus haut", "Une quinte plus bas"], a: 1, fb: "La clarinette en Sib est un instrument transpositeur : ce qui est noté Do sonne Sib à l'oreille. Pour que le clarinettiste joue en Do majeur avec les cordes, le chef lui donne une partie notée un ton plus haut (Ré majeur). Cette transposition existe pour raisons historiques de construction de l'instrument." },
  { q: "Les trois registres de la clarinette sont :", opts: ["Grave, médium, aigu (uniformes)", "Chalumeau (grave, sombre), clarinon (médium, clair), aigu (perçant) — trois couleurs très distinctes", "Forte, mezzo, piano", "Monodique, harmonique, polyphonique"], a: 1, fb: "La clarinette a trois registres acoustiquement très distincts : chalumeau (grave, La3–Mi4, velouté et sombre), médium/clarinon (Fa4–Si4, clarté du registre normal), aigu (Do5–Sib6, de brillant à perçant). Cette hétérogénéité est un défi et une richesse pour le compositeur." },
  { q: "Le basson joue quel rôle principal dans l'orchestre ?", opts: ["Mélodie soprano", "Basse des bois, contrepoint grave, et coloriste humoristique en aigu", "Solo de fanfare", "Doublure de la flûte"], a: 1, fb: "Le basson est la basse des bois et un contrepointiste précieux. En grave (Sib1–Fa2), il fonde la section des bois. En médium, il joue des lignes de contrepoint. En aigu, son timbre devient légèrement comique ou plaintif — Dukas l'utilise pour l'apprenti sorcier, Prokofiev pour le grand-père dans Pierre et le Loup." },

  // Cuivres
  { q: "Quel instrument de cuivre est décrit comme le 'lien' entre cuivres et bois ?", opts: ["La trompette", "Le cor (french horn) — son timbre peut se fondre aussi bien avec les bois qu'avec les cuivres", "Le trombone", "Le tuba"], a: 1, fb: "Le cor a un timbre unique : joué doucement (bouché ou en harmoniques), il se fond avec les bois et les cordes. Joué ouvertement fort, il sonne comme un cuivre. Cette polyvalence en fait le trait d'union de l'orchestre. Brahms l'aimait particulièrement pour ses lignes lyriques et ses harmonies fondues." },
  { q: "La trompette est connue pour :", opts: ["Son timbre grave et noble", "Son éclat et sa brillance — tranchante en aigu, idéale pour les fanfares et les mélodies héroïques", "Sa douceur en pianissimo", "Son caractère comique"], a: 1, fb: "La trompette est l'instrument des fanfares, des appels militaires et des lignes héroïques. Son timbre éclatant en forte est incomparable — mais elle peut aussi jouer pianissimo avec une sourdine (son métallique et lointain). Utilisée avec parcimonie, elle marque les moments clés." },
  { q: "Le trombone est le seul instrument de cuivre qui peut :", opts: ["Jouer en pizzicato", "Produire un glissando continu — grâce à la coulisse qui fait varier la longueur du tube", "Jouer à 3 parties simultanément", "S'accorder librement en temps réel"], a: 1, fb: "La coulisse du trombone est unique dans les cuivres : en la faisant glisser, on obtient un glissando continu (portamento), impossible sur trompette ou cor. Cette technique est utilisée pour des effets dramatiques (jazz, Stockhausen) et pour les passages lyriques où la voix humaine semble glisser d'une note à l'autre." },
  { q: "Pourquoi le tuba est-il indispensable dans l'orchestre ?", opts: ["Il joue la mélodie principale", "Il fonde la harmonie grave des cuivres — sans lui, la base des cuivres manque de profondeur et d'assise", "Il remplace la contrebasse", "Il est uniquement percussif"], a: 1, fb: "Le tuba est la fondation des cuivres : sans lui, les trombones manquent d'assise dans le grave. Il double souvent la contrebasse ou joue une basse indépendante. Composé de nombreux tubes repliés sur eux-mêmes, c'est l'instrument le plus grave et le plus puissant des cuivres." },
  { q: "Pourquoi les cuivres doivent-ils souvent jouer moins fort que leur dynamique naturelle ?", opts: ["Par convention musicale", "Parce qu'ils sont acoustiquement beaucoup plus puissants que les cordes et les bois — jouer fortissimo couvrirait complètement les autres sections", "Parce qu'ils fatiguent vite", "Parce que le chef le demande toujours"], a: 1, fb: "L'acoustique des cuivres est radicalement différente de celle des cordes. Un seul trompettiste fortissimo peut couvrir 30 violonistes forte. L'orchestrateur doit donc constamment compenser : notions de 'piano pour les cuivres' en cas de doublure avec les cordes, et réserver le fortissimo aux tutti de grande puissance." },

  // Percussions
  { q: "Les timbales sont classées comme instruments à son :", opts: ["Indéterminé (comme la caisse claire)", "Déterminé — on peut régler leur hauteur (généralement entre Do2 et La3)", "Indéfini selon le morceau", "Uniquement rythmique"], a: 1, fb: "Les timbales (kettledrums) ont une hauteur déterminée réglable par une pédale : on peut changer de note pendant la pièce. Un orchestre utilise généralement 2 à 5 timbales couvrant Do2–La3 environ. Beethoven leur a assigné des rôles mélodiques et harmoniques précis (ex. Concerto pour violon en Ré mineur — tension sur Ré et La)." },
  { q: "La caisse claire apporte principalement :", opts: ["Des sons longs et chantants", "Une articulation rythmique tranchante — roulements, flams, accentuations militaires", "Des harmonies graves", "Une couleur douce et intimiste"], a: 1, fb: "La caisse claire (snare drum) est l'instrument de la précision rythmique : roulements rapides, accents syncopés, figures militaires. Sa présence marque les moments d'énergie et d'articulation. Ravel l'utilise tout au long du Boléro pour maintenir le rythme ostinato caractéristique." },
  { q: "Quelle est la différence principale entre les percussions à son déterminé et indéterminé ?", opts: ["La taille de l'instrument", "Les instruments à son déterminé jouent des hauteurs précises (timbales, xylophone, marimba) ; les indéterminés apportent timbre et rythme sans hauteur fixe (caisse claire, cymbales)", "Le matériau de fabrication", "Il n'y a aucune différence musicale"], a: 1, fb: "Distinction fondamentale : instruments à son déterminé (timbales, xylophone, vibraphone, marimba, glockenspiel) jouent des hauteurs musicales précises et peuvent participer à l'harmonie. Instruments à son indéterminé (caisse claire, grosse caisse, cymbales, tam-tam) apportent couleur, rythme et texture." },

  // Doublures
  { q: "Quelle combinaison de doublure produit le son le plus 'fondu' et arrondi ?", opts: ["Cordes + Cuivres", "Cordes + Bois — leurs timbres se mélangent naturellement sans que l'un domine l'autre", "Bois + Cuivres", "Percussions + Cordes"], a: 1, fb: "Cordes + Bois forment la combinaison de doublure la plus douce. Les cordes arrondissent le timbre des bois ; les bois précisent l'intonation des cordes. C'est la doublure préférée dans les passages lyriques. Cordes + Cuivres est plus puissant mais moins fondu." },
  { q: "La 'doublure à l'octave' (superoctave) produit quel effet ?", opts: ["Aucun changement sonore perceptible", "Un approfondissement (octave grave) ou un éclaircissement (octave aiguë) du son — sans changer la couleur harmonique", "Un changement de tonalité", "Un accord dissonant"], a: 1, fb: "La doublure à l'octave enrichit le timbre : ajouter l'octave grave (ex. basson doublet la clarinette) profondeur et chaleur ; ajouter l'octave aiguë (ex. flûte doublet le violon) apporte brillance et projection. L'harmonie ne change pas — seule la couleur de l'instrument change." },
  { q: "Pourquoi éviter de doubler les cuivres fortissimo sur les bois ?", opts: ["Par convention stylistique uniquement", "Les cuivres fortissimo couvrent complètement les bois — ces derniers deviennent inaudibles", "Les bois sonnent mieux seuls", "Les cuivres changent la tonalité des bois"], a: 1, fb: "L'acoustique est sans pitié : un trompettiste ou tromboniste fortissimo produit un volume sonore plusieurs fois supérieur à un hautboïste ou clarinettiste. En cas de doublure forte, les bois disparaissent sous les cuivres. La solution : les cuivres jouent mezzo-forte, les bois forte." },
  { q: "La doublure à l'unisson (deux instruments, même hauteur) sert à :", opts: ["Changer l'harmonie", "Renforcer la puissance et la projection sans modifier le caractère mélodique ni l'harmonie", "Créer de la dissonance", "Transposer d'une octave"], a: 1, fb: "La doublure à l'unisson additionne les volumes sans modifier l'harmonie ni le caractère. Elle est utilisée pour renforcer une ligne principale (mélodie doublée à l'unisson par plusieurs instruments = projection maximale), ou pour fusionner les couleurs de timbre de deux instruments différents." },
  { q: "Pour un passage orchestral lyrique et doux, quelle doublure est la plus appropriée ?", opts: ["Trompette + Trombone fortissimo", "Violons + Flûtes ou hautbois — cordes + bois en nuance douce", "Tuba + Grosse caisse", "Cuivres tutti"], a: 1, fb: "Pour un passage doux et lyrique, cordes + bois (flûte, hautbois, clarinette) en dynamique douce est la combinaison idéale. Les timbres se fondent naturellement, le résultat est arrondi et chantant. Les cuivres sont réservés aux climax ou utilisés pianissimo avec sourdine pour une couleur lointaine." },

  // Équilibre
  { q: "Dans le Boléro de Ravel, la même mélodie et harmonie sont répétées 18 fois pour démontrer :", opts: ["La répétition motivique", "L'enrichissement orchestral progressif — chaque répétition ajoute des instruments, illustrant comment l'orchestration transforme une idée simple", "La forme rondo", "La substitution tritonique"], a: 1, fb: "Le Boléro (1928) est l'étude d'orchestration la plus célèbre du répertoire : même mélodie (en ut majeur), même harmonie, même rythme de caisse claire — seule l'orchestration change à chaque cycle. On entend successivement chaque instrument de l'orchestre, puis leurs combinaisons de plus en plus riches." },
  { q: "Pourquoi le piano est-il rarement doublé en unisson à l'orchestre ?", opts: ["Par convention stylistique", "Car son timbre percussif et son attaque brusque ne se fondent pas naturellement avec les cordes et les bois", "Car il est trop doux", "Car il change la tonalité"], a: 1, fb: "Le piano a un timbre percussif (enveloppe attack-decay rapide) très différent des cordes et des bois (son continu). En doublure, ce contraste crée un clash plutôt qu'une fusion. À l'orchestre, le piano est généralement utilisé en soliste (concerto), en couleur percussive ponctuelle, ou en rôle autonome." },
  { q: "Quel est l'instrument le plus puissant de l'orchestre ?", opts: ["La grosse caisse", "La trompette (ou les cuivres en général) — ils dominent acoustiquement toutes les autres familles en fortissimo", "Le violon (car il est le plus nombreux)", "La contrebasse"], a: 1, fb: "Les cuivres sont les instruments les plus puissants de l'orchestre, et la trompette est souvent la plus perçante. Un seul trompettiste fortissimo peut couvrir un pupitre complet de violons. Cette puissance acoustique impose à l'orchestrateur de traiter les cuivres avec parcimonie pour maintenir l'équilibre." },
  { q: "Comment Debussy équilibre-t-il les textures dans le Prélude à l'après-midi d'un faune ?", opts: ["En utilisant des cuivres fortissimo", "En gardant les cuivres très discrets, favorisant les textures légères de bois et cordes avec pédale de harpe", "En utilisant uniquement des cordes", "En supprimant toutes les percussions"], a: 1, fb: "Le Prélude à l'après-midi d'un faune (1894) est un modèle d'orchestration impressionniste : flûte solo, harpe, cordes en sourdine, bois en demi-teintes. Debussy utilise les cuivres très parcimonieusement pour garder la texture transparente — l'opposé de Beethoven ou Wagner." },

  // Registres
  { q: "Quel registre correspond à la voix de soprano dans l'orchestre ?", opts: ["Violoncelle et basson", "Violon I, flûte, hautbois, trompette — instruments à tessiture aiguë", "Cor et alto", "Tuba et contrebasse"], a: 1, fb: "Le registre soprano (voix haute) est couvert par : Violon I (Sol3–Mi6), Flûte (Do4–Do7), Hautbois (Sib3–La6), Trompette (Fa#3–Do6). Ce registre aiguporte la mélodie principale dans la plupart des textures orchestrales standard." },
  { q: "Quel registre correspond à la voix de basse dans l'orchestre ?", opts: ["Violon II et clarinette", "Contrebasse, tuba, basson grave — instruments à tessiture très grave", "Alto et cor", "Trombone et hautbois"], a: 1, fb: "Le registre basse est assuré par : Contrebasse (Mi1–Sol4, sonne 8ve plus bas), Tuba (Sib0–Fa4), Basson grave (Sib1–Mi3), Contrebasson (Sib0–Mi3). Ces instruments fondent la pyramide harmonique de l'orchestre — sans eux, le son manque d'assise." },
  { q: "Pourquoi faut-il 'espacer' les voix dans le grave davantage que dans l'aigu ?", opts: ["Par convention uniquement", "Car en grave, les intervalles resserés créent de la boue sonore — les harmoniques se confondent. En aigu, les tierces et secondes sonnent claires", "Car les instruments graves sont plus gros", "Car les harmoniques graves sont moins nombreuses"], a: 1, fb: "Physique acoustique fondamentale : les harmoniques des notes graves sont plus denses et se chevauchent davantage. Un accord Do2–Mi2 (tierce mineure en grave) sonne boueux ; Do5–Mi5 sonne clair. Règle d'or : plus on est grave, plus on espace les voix (quintes, octaves) ; en aigu, les secondes et tierces sont acceptables." },
  { q: "Un 'trou' harmonique dans l'orchestration désigne :", opts: ["Un silence dans la partition", "Un registre non couvert par aucun instrument — le spectre sonore a une zone vide, créant un son déséquilibré", "Un accord diminué", "Une modulation manquée"], a: 1, fb: "Un trou harmonique survient quand le registre médium n'est pas couvert alors que le grave et l'aigu sont présents. Le son semble 'creux' — on entend la basse et le soprano mais pas le milieu. Solution : ajouter des instruments dans le registre intermédiaire (alto, clarinette, cor, violoncelle médium)." },

  // SATB → Orchestre
  { q: "Dans la correspondance SATB → orchestre, la voix de ténor (T) est assurée par :", opts: ["Violon I et flûte", "Violoncelle, trombone, basson — registre Do3–Fa4 environ", "Cor et alto", "Hautbois et clarinette"], a: 1, fb: "La voix de ténor correspond à : Violoncelle (registre médium Do3–Mi5), Trombone (Mi2–Fa4, registre ténor principal), Basson (registre médium Ré3–Mib5). Ces instruments assurent la troisième voix (ténor) dans les textures à 4 parties distribuées à l'orchestre." },
  { q: "Pour orchestrer un choral à 4 voix (SATB), on distribuera la voix de soprano à :", opts: ["Tuba et contrebasse", "Violon I, flûte ou hautbois — instruments dont la tessiture aiguë correspond à la voix soprano", "Basson et trombone", "Alto et clarinette grave"], a: 1, fb: "Soprano (voix la plus aiguë) → Violon I (Sol3–Mi6), Flûte (Do4–Do7), Hautbois (Sib3–La6) ou Trompette. Ces instruments ont la brillance et la tessiture pour porter la ligne mélodique principale avec clarté et projection." },

  // Ravel
  { q: "Maurice Ravel est surtout célèbre pour quel chef-d'œuvre d'orchestration ?", opts: ["La Symphonie n°5 en Do mineur", "Le Boléro — étude d'orchestration progressive sur un ostinato rythmique et une mélodie répétée 18 fois", "Le Requiem", "La Symphonie Fantastique"], a: 1, fb: "Le Boléro (1928) est la composition la plus jouée de Ravel et l'une des plus connues du répertoire orchestral. Conçu initialement comme une commande de Ida Rubinstein, il est devenu une démonstration parfaite de l'orchestration progressive : seul le timbre change, pas la mélodie ni l'harmonie." },
  { q: "Ravel a orchestré pour orchestre une œuvre célèbre de quel compositeur ?", opts: ["Bach", "Mussorgsky — Tableaux d'une exposition, transcription de l'original pour piano en chef-d'œuvre orchestral", "Beethoven", "Schubert"], a: 1, fb: "Tableaux d'une exposition (1874) de Moussorgsky était une suite pour piano. En 1922, Ravel en fait une orchestration considérée comme l'une des plus brillantes du répertoire. Il exploite chaque famille d'instruments pour illustrer chaque tableau : le saxo pour 'Le vieux château', les trompettes pour la 'Grande Porte de Kiev'." },
  { q: "Le Prélude à l'après-midi d'un faune de Debussy commence par :", opts: ["Un accord fortissimo de cuivres", "Un solo de flûte non accompagné — mélodie chromatique, douce et flottante", "Un rythme de timbales", "Un accord de cordes pianissimo"], a: 1, fb: "L'œuvre ouvre sur un solo de flûte — mélodie chromatique (La4–Mi4), pianissimo, lente, évocatrice. Ce début révolutionnaire (1894) illustre la vision impressionniste : la couleur instrumentale (flûte = air, lumière, nature) est au service de l'évocation, pas du développement motivique." },
  { q: "Ravel est considéré comme un génie de l'orchestration parce que :", opts: ["Il composait plus vite que les autres", "Il avait une maîtrise exceptionnelle des timbres et des combinaisons instrumentales — chaque instrument dans son registre idéal, chaque couleur à sa juste place", "Il utilisait toujours tous les instruments", "Il évitait les cuivres"], a: 1, fb: "Ravel avait un sens exceptionnel du 'placement' instrumental — chaque instrument dans son registre de prédilection, chaque combinaison de timbres calculée pour l'effet maximum. Son orchestration de Tableaux est un manuel vivant : on peut y lire comment il utilise chaque instrument pour sa couleur spécifique." },
  { q: "Ravel vivait à quelle époque ?", opts: ["Baroque (1600–1750)", "Classicisme (1750–1820)", "Romantisme tardif / Impressionnisme (1875–1937)", "Contemporain (après 1950)"], a: 2, fb: "Maurice Ravel (1875–1937) appartient à la période de l'impressionnisme musical (avec Debussy, son contemporain). Il est connu pour sa précision stylistique, son sens de l'humour, ses œuvres pour piano (Gaspard de la Nuit) et son orchestration inégalée (Boléro, La Valse, orchestration des Tableaux de Moussorgski)." },

  // Piano
  { q: "La pédale de résonance du piano sert à :", opts: ["Changer la tonalité", "Lever les étouffoirs — les notes résonnent librement, se superposant et créant une richesse harmonique et de résonance", "Rendre le son plus sec", "Changer le registre"], a: 1, fb: "La pédale de résonance (pédale droite) lève tous les étouffoirs : les cordes vibrent librement, y compris celles des notes non jouées (résonance sympathique). Cela crée une résonance chaleureuse et permettde connecter les harmonies. Utilisée avec excès, elle crée de la boue sonore ; utilisée avec art (Chopin, Debussy), elle enrichit considérablement le timbre." },
  { q: "Dans l'écriture pianistique standard, la main gauche gère généralement :", opts: ["La mélodie principale uniquement", "La basse et l'accompagnement harmonique — laissant la main droite libre pour la mélodie", "Les ornements uniquement", "Le registre aigu"], a: 1, fb: "La division main droite / main gauche au piano est fondamentale : main droite = mélodie (registre médium-aigu, Do4–Do6 environ) ; main gauche = basse + accompagnement (registre La0–Do4). Cette division permet à un seul musicien de jouer simultanément mélodie, harmonie et basse — un ensemble complet." },
  { q: "Pourquoi faut-il éviter d'écrire trop de notes dans le grave du piano ?", opts: ["Par convention de notation", "Car les harmoniques des notes graves se superposent et créent de la boue sonore — les accords serrés en grave sonnent flous", "Car le registre grave est réservé au pouce", "Car les cordes graves sont moins nombreuses"], a: 1, fb: "En grave (Do1–Do3), les harmoniques des notes sont nombreuses et très proches. Des accords serrés (Do1–Ré1–Mi1) créent une boue sonore où les notes se confondent. Solution : espacement large en grave (octaves, quintes), accords plus serrés en médium-aigu. Chopin et Ravel maîtrisent parfaitement cette règle." },

  // Chambre
  { q: "La formation 'quatuor à cordes' est composée de :", opts: ["4 violons", "2 violons, 1 alto, 1 violoncelle — la formation de chambre la plus emblématique", "2 violons, 2 violoncelles", "Violon, alto, violoncelle, contrebasse"], a: 1, fb: "Le quatuor à cordes (2 violons, alto, violoncelle) est la formation de chambre la plus importante du répertoire classique. Il couvre un large spectre (Sol3–La7 au-dessus, Do2–Sol5 en dessous) avec une homogénéité de timbre unique. Haydn, Mozart, Beethoven et Schubert y ont écrit leurs pages les plus intimes." },
  { q: "Un 'trio avec piano' (piano trio) est formé de :", opts: ["3 pianos", "Piano, violon, violoncelle — formation de chambre très fréquente dans le répertoire classique et romantique", "Piano, flûte, clarinette", "Piano, violon, alto"], a: 1, fb: "Le trio avec piano (piano, violon, violoncelle) est l'une des formations de chambre les plus fréquentes. Beethoven, Schubert, Brahms, Ravel y ont écrit des chefs-d'œuvre. L'équilibre y est délicat : le piano peut facilement couvrir le violon et le violoncelle s'il joue trop fort." },
  { q: "En musique de chambre, l'équilibre dynamique entre musiciens est :", opts: ["Géré par un chef d'orchestre", "La responsabilité de chaque musicien — il n'y a pas de chef, chacun doit écouter et adapter son volume", "Fixé par le compositeur avec des métronomes", "Non important — c'est une petite formation"], a: 1, fb: "En musique de chambre, il n'y a pas de chef : l'équilibre est la responsabilité collective des musiciens. Chacun doit écouter les autres et adapter en permanence son volume, son phrasé et sa dynamique. C'est une forme de conversation musicale — chaque instrument est à la fois narrateur et auditeur." },
];

const questionsEn: Question[] = [
  { q: "How many large families make up the symphony orchestra?", opts: ["2 (strings and brass)", "3 (strings, woodwinds, brass)", "4 (strings, woodwinds, brass, percussion)", "5 (+ piano)"], a: 2, fb: "The symphony orchestra has 4 families: strings (violins, violas, cellos, double basses), woodwinds (flute, oboe, clarinet, bassoon), brass (horn, trumpet, trombone, tuba), percussion (timpani, snare drum, cymbals...). Harp, piano or guitar may be added depending on the work." },
  { q: "Which family forms the 'backbone' of the orchestra?", opts: ["The brass", "The percussion", "The strings — most numerous and most consistently present", "The woodwinds"], a: 2, fb: "The strings form the foundation of the orchestra: they are by far the most numerous (a large orchestra has 60+ string players out of ~100). Their homogeneous timbre allows for blends and crescendos impossible with other families." },
  { q: "Woodwinds are called so because:", opts: ["They play forest music", "Historically made of wood — though modern flutes and saxophones are often metal", "They are always played outdoors", "They always produce a soft sound"], a: 1, fb: "Woodwinds are named after their historical material. Today, flutes are generally metal (silver, gold) and saxophones too — but they remain classified as woodwinds because of their sound production mechanism (air column in a tube)." },
  { q: "What is the practical range of the violin?", opts: ["C2 – G4 (low register)", "G3 – E6 approximately (soprano register)", "C1 – C5 (wide range)", "A3 – A6 (medium)"], a: 1, fb: "The violin covers approximately G3–E6 (with extensions to A7 for virtuosos). It is the soprano melody instrument par excellence. It has two sections: Violin I (main melody) and Violin II (upper harmony)." },
  { q: "Which string instrument has the darkest and most intermediate timbre?", opts: ["The violin", "The viola", "The cello", "The double bass"], a: 1, fb: "The viola has a dark, warm and slightly nasal timbre — often described as the most 'human' of the strings. Its intermediate range (approximately C3–A5) and distinctive timbre make it the instrument of alto harmony and expressive counter-melodies." },
  { q: "The cello plays what main role in the orchestra?", opts: ["Soprano melody only", "Deep melody and singing bass — capable of expressive lyrical lines in its medium register", "Rhythmic accompaniment only", "Doubling the brass"], a: 1, fb: "The cello is one of the most versatile instruments: harmonic bass (C2–B2), counterpoint (medium), and lyrical melody (E3–A5). Its ability to sing in the tenor register has made it a favorite for principal themes (Dvořák Concerto, Bach suites)." },
  { q: "The double bass sounds at what pitch relative to the notation?", opts: ["As written", "One octave lower than notated", "A fifth lower", "A third higher"], a: 1, fb: "The double bass is a transposing instrument at the lower octave: what is notated as C3 sounds as C2. This convention simplifies reading (avoids too many ledger lines). Its main role is the harmonic foundation of the bass register." },
  { q: "'Pizzicato' for strings means:", opts: ["Playing with the bow", "Plucking the strings with the fingers — a percussive technique, shorter and drier than the bow", "Playing very softly", "Playing with a mute"], a: 1, fb: "Pizzicato means plucking the strings (without the bow). It produces a brief, dry attack — widely used in dance accompaniments, jazz pizzicato (double bass), and orchestral color effects. Bartók developed the 'snap pizzicato' (slapped against the fingerboard)." },
  { q: "The bow (arco) on strings produces:", opts: ["A brief, dry sound", "A continuous sound — the friction of the horsehair on the string creates sustained vibration", "A plucked sound", "A percussive sound"], a: 1, fb: "The bow (arco) produces continuous sound by friction of horsehair on the string. This capacity for sustained sound distinguishes strings from short-attack instruments. Détaché, legato, spiccato and col legno (with the wood of the bow) are variations of bowing technique." },
  { q: "What is the characteristic timbre of the flute in the high register?", opts: ["Dark and deep", "Airy, luminous, brilliant — often used for ethereal textures", "Nasal and poignant", "Massive and powerful"], a: 1, fb: "In the high register, the flute is luminous and airy — ideal for Impressionist textures (Debussy's Prélude à l'après-midi d'un faune begins with a flute solo). In the low register (foot joint), it is veiled and mysterious. It is the most agile of the woodwinds." },
  { q: "Which wind instrument is most expressive for lyrical and poignant solos?", opts: ["The flute", "The oboe — its nasal and penetrating timbre makes it inimitable in expressive melodies", "The clarinet", "The bassoon"], a: 1, fb: "The oboe has the timbre closest to the nasal human voice. It has a very distinctive sound, recognizable even mixed with strings. Famous solos: Albinoni's Concerto in A minor, Bach's Brandenburg Concerto No.2, Brahms' 4th Symphony." },
  { q: "The Bb clarinet transposes its notes at what pitch?", opts: ["As written", "One tone lower than written (C sounds as Bb)", "One tone higher", "A fifth lower"], a: 1, fb: "The Bb clarinet is a transposing instrument: what is notated as C sounds as Bb. For the clarinetist to play in C major with the strings, the conductor gives them a part notated one tone higher (D major). This transposition exists for historical reasons of instrument construction." },
  { q: "The three registers of the clarinet are:", opts: ["Low, medium, high (uniform)", "Chalumeau (low, dark), clarion (medium, clear), high (piercing) — three very distinct colors", "Forte, mezzo, piano", "Monodic, harmonic, polyphonic"], a: 1, fb: "The clarinet has three acoustically very distinct registers: chalumeau (low, A3–E4, velvety and dark), medium/clarion (F4–B4, clarity of the normal register), high (C5–Bb6, from brilliant to piercing). This heterogeneity is both a challenge and an asset for the composer." },
  { q: "The bassoon plays what main role in the orchestra?", opts: ["Soprano melody", "Bass of the woodwinds, bass counterpoint, and humorous colorist in the high register", "Fanfare solo", "Doubling the flute"], a: 1, fb: "The bassoon is the bass of the woodwinds and a valuable contrapuntist. In the bass (Bb1–F2), it underpins the woodwind section. In the medium, it plays counterpoint lines. In the high register, its timbre becomes slightly comic or plaintive — Dukas uses it for the Sorcerer's Apprentice, Prokofiev for the grandfather in Peter and the Wolf." },
  { q: "Which brass instrument is described as the 'link' between brass and woodwinds?", opts: ["The trumpet", "The French horn — its timbre can blend as well with woodwinds as with brass", "The trombone", "The tuba"], a: 1, fb: "The horn has a unique timbre: played softly (stopped or in harmonics), it blends with woodwinds and strings. Played openly loud, it sounds like a brass. This versatility makes it the bridge of the orchestra. Brahms particularly loved it for its lyrical lines and blended harmonies." },
  { q: "The trumpet is known for:", opts: ["Its deep and noble timbre", "Its brilliance — cutting in the high register, ideal for fanfares and heroic melodies", "Its softness in pianissimo", "Its comic character"], a: 1, fb: "The trumpet is the instrument of fanfares, military calls and heroic lines. Its brilliant fortissimo timbre is incomparable — but it can also play pianissimo with a mute (metallic, distant sound). Used sparingly, it marks key moments." },
  { q: "The trombone is the only brass instrument that can:", opts: ["Play pizzicato", "Produce a continuous glissando — thanks to the slide that varies the tube length", "Play 3 parts simultaneously", "Tune freely in real time"], a: 1, fb: "The trombone's slide is unique in brass: sliding it produces a continuous glissando (portamento), impossible on trumpet or horn. This technique is used for dramatic effects (jazz, Stockhausen) and for lyrical passages where the human voice seems to glide from note to note." },
  { q: "Why is the tuba indispensable in the orchestra?", opts: ["It plays the main melody", "It founds the bass harmony of the brass — without it, the brass base lacks depth and grounding", "It replaces the double bass", "It is purely percussive"], a: 1, fb: "The tuba is the foundation of the brass: without it, the trombones lack grounding in the bass. It often doubles the double bass or plays an independent bass. Composed of many coiled tubes, it is the lowest and most powerful brass instrument." },
  { q: "Why must brass often play softer than their natural dynamic?", opts: ["By musical convention", "Because they are acoustically much more powerful than strings and woodwinds — playing fortissimo would completely cover the other sections", "Because they tire quickly", "Because the conductor always requests it"], a: 1, fb: "The acoustics of brass are radically different from strings. A single trumpeter fortissimo can cover 30 forte violinists. The orchestrator must constantly compensate: 'piano for the brass' when doubling with strings, and reserve fortissimo for high-power tutti passages." },
  { q: "Timpani are classified as instruments with:", opts: ["Undetermined pitch (like the snare drum)", "Determined pitch — their tuning can be set (generally between C2 and A3)", "Indefinite pitch depending on the piece", "Purely rhythmic function"], a: 1, fb: "Timpani (kettledrums) have a determined, adjustable pitch via a pedal: the note can be changed during the piece. An orchestra generally uses 2 to 5 timpani covering approximately C2–A3. Beethoven assigned them precise melodic and harmonic roles (e.g. Violin Concerto in D minor — tension on D and A)." },
  { q: "The snare drum mainly brings:", opts: ["Long, singing sounds", "Sharp rhythmic articulation — rolls, flams, military accents", "Deep harmonies", "A soft, intimate color"], a: 1, fb: "The snare drum is the instrument of rhythmic precision: rapid rolls, syncopated accents, military figures. Its presence marks moments of energy and articulation. Ravel uses it throughout the Bolero to maintain the characteristic ostinato rhythm." },
  { q: "What is the main difference between determined and undetermined percussion?", opts: ["The size of the instrument", "Determined instruments play precise pitches (timpani, xylophone, marimba); undetermined ones bring timbre and rhythm without fixed pitch (snare drum, cymbals)", "The manufacturing material", "There is no musical difference"], a: 1, fb: "Fundamental distinction: determined instruments (timpani, xylophone, vibraphone, marimba, glockenspiel) play precise musical pitches and can participate in harmony. Undetermined instruments (snare drum, bass drum, cymbals, tam-tam) bring color, rhythm and texture." },
  { q: "Which doubling combination produces the most 'blended' and rounded sound?", opts: ["Strings + Brass", "Strings + Woodwinds — their timbres mix naturally without one dominating the other", "Woodwinds + Brass", "Percussion + Strings"], a: 1, fb: "Strings + Woodwinds form the softest doubling combination. The strings round off the woodwind timbre; the woodwinds sharpen the intonation of the strings. It is the preferred doubling for lyrical passages. Strings + Brass is more powerful but less blended." },
  { q: "'Octave doubling' (superoctave) produces what effect?", opts: ["No perceptible sound change", "A deepening (lower octave) or brightening (upper octave) of the sound — without changing the harmonic color", "A key change", "A dissonant chord"], a: 1, fb: "Octave doubling enriches the timbre: adding the lower octave (e.g. bassoon doubling the clarinet) brings depth and warmth; adding the upper octave (e.g. flute doubling the violin) brings brilliance and projection. The harmony does not change — only the instrumental color changes." },
  { q: "Why avoid doubling brass fortissimo on woodwinds?", opts: ["By stylistic convention only", "Brass fortissimo completely covers the woodwinds — the latter become inaudible", "Woodwinds sound better alone", "Brass changes the key of the woodwinds"], a: 1, fb: "Acoustics are unforgiving: a trumpeter or trombonist fortissimo produces a sound volume many times greater than an oboist or clarinetist. In forte doubling, the woodwinds disappear beneath the brass. The solution: brass plays mezzo-forte, woodwinds forte." },
  { q: "Unison doubling (two instruments, same pitch) serves to:", opts: ["Change the harmony", "Reinforce power and projection without modifying the melodic character or harmony", "Create dissonance", "Transpose by an octave"], a: 1, fb: "Unison doubling adds volumes without modifying harmony or character. It is used to strengthen a main line (melody doubled in unison by several instruments = maximum projection), or to fuse the timbre colors of two different instruments." },
  { q: "For a lyrical and soft orchestral passage, what doubling is most appropriate?", opts: ["Trumpet + Trombone fortissimo", "Violins + Flutes or oboe — strings + woodwinds in soft dynamics", "Tuba + Bass drum", "Brass tutti"], a: 1, fb: "For a soft and lyrical passage, strings + woodwinds (flute, oboe, clarinet) in soft dynamics is the ideal combination. The timbres blend naturally, the result is rounded and singing. Brass is reserved for climaxes or used pianissimo with mute for a distant color." },
  { q: "In Ravel's Bolero, the same melody and harmony are repeated 18 times to demonstrate:", opts: ["Motivic repetition", "Progressive orchestral enrichment — each repetition adds instruments, illustrating how orchestration transforms a simple idea", "Rondo form", "Tritone substitution"], a: 1, fb: "The Bolero (1928) is the most famous orchestration study in the repertoire: same melody (in C major), same harmony, same snare drum rhythm — only the orchestration changes each cycle. Each instrument of the orchestra is heard successively, then in increasingly rich combinations." },
  { q: "Why is the piano rarely doubled in unison at the orchestra?", opts: ["By stylistic convention", "Because its percussive timbre and abrupt attack do not blend naturally with strings and woodwinds", "Because it is too soft", "Because it changes the key"], a: 1, fb: "The piano has a percussive timbre (fast attack-decay envelope) very different from strings and woodwinds (continuous sound). In doubling, this contrast creates a clash rather than a fusion. In the orchestra, piano is generally used as soloist (concerto), as punctual percussive color, or in an autonomous role." },
  { q: "Which is the most powerful instrument in the orchestra?", opts: ["The bass drum", "The trumpet (or brass in general) — they acoustically dominate all other families in fortissimo", "The violin (because it is the most numerous)", "The double bass"], a: 1, fb: "Brass are the most powerful instruments in the orchestra, and the trumpet is often the most piercing. A single fortissimo trumpeter can cover a full section of violins. This acoustic power requires the orchestrator to treat brass sparingly to maintain balance." },
  { q: "How does Debussy balance textures in the Prélude à l'après-midi d'un faune?", opts: ["By using brass fortissimo", "By keeping brass very discreet, favoring light woodwind and string textures with harp pedal", "By using strings only", "By removing all percussion"], a: 1, fb: "The Prélude à l'après-midi d'un faune (1894) is a model of Impressionist orchestration: flute solo, harp, muted strings, woodwinds in half-tints. Debussy uses brass very sparingly to keep the texture transparent — the opposite of Beethoven or Wagner." },
  { q: "Which register corresponds to the soprano voice in the orchestra?", opts: ["Cello and bassoon", "Violin I, flute, oboe, trumpet — high-range instruments", "Horn and viola", "Tuba and double bass"], a: 1, fb: "The soprano register (high voice) is covered by: Violin I (G3–E6), Flute (C4–C7), Oboe (Bb3–A6), Trumpet (F#3–C6). This high register carries the main melody in most standard orchestral textures." },
  { q: "Which register corresponds to the bass voice in the orchestra?", opts: ["Violin II and clarinet", "Double bass, tuba, bass bassoon — instruments with very low range", "Viola and horn", "Trombone and oboe"], a: 1, fb: "The bass register is covered by: Double bass (E1–G4, sounds 8va lower), Tuba (Bb0–F4), Bassoon bass (Bb1–E3), Contrabassoon (Bb0–E3). These instruments found the harmonic pyramid of the orchestra — without them, the sound lacks grounding." },
  { q: "Why must voices be more 'spread out' in the bass than in the treble?", opts: ["By convention only", "Because in the bass, close intervals create muddy sound — harmonics overlap. In the treble, thirds and seconds sound clear", "Because bass instruments are larger", "Because bass harmonics are fewer"], a: 1, fb: "Fundamental acoustic physics: harmonics of bass notes are denser and overlap more. A chord C2–E2 (minor third in the bass) sounds muddy; C5–E5 sounds clear. Golden rule: the lower you go, the wider you space the voices (fifths, octaves); in the treble, seconds and thirds are acceptable." },
  { q: "A 'harmonic gap' in orchestration refers to:", opts: ["A silence in the score", "A register covered by no instrument — the sound spectrum has an empty zone, creating an unbalanced sound", "A diminished chord", "A missed modulation"], a: 1, fb: "A harmonic gap occurs when the medium register is not covered while bass and treble are present. The sound seems 'hollow' — you hear the bass and soprano but not the middle. Solution: add instruments in the intermediate register (viola, clarinet, horn, medium cello)." },
  { q: "In the SATB → orchestra mapping, the tenor voice (T) is covered by:", opts: ["Violin I and flute", "Cello, trombone, bassoon — approximately C3–F4 range", "Horn and viola", "Oboe and clarinet"], a: 1, fb: "The tenor voice corresponds to: Cello (medium range C3–E5), Trombone (E2–F4, main tenor register), Bassoon (medium range D3–Eb5). These instruments provide the third voice (tenor) in 4-part textures distributed across the orchestra." },
  { q: "To orchestrate a 4-voice chorale (SATB), the soprano voice is given to:", opts: ["Tuba and double bass", "Violin I, flute or oboe — instruments whose high range corresponds to the soprano voice", "Bassoon and trombone", "Viola and bass clarinet"], a: 1, fb: "Soprano (highest voice) → Violin I (G3–E6), Flute (C4–C7), Oboe (Bb3–A6) or Trumpet. These instruments have the brilliance and range to carry the main melodic line with clarity and projection." },
  { q: "Ravel is most famous for which masterpiece of orchestration?", opts: ["Symphony No.5 in C minor", "The Bolero — a progressive orchestration study on a rhythmic ostinato and a melody repeated 18 times", "The Requiem", "Symphonie Fantastique"], a: 1, fb: "The Bolero (1928) is Ravel's most performed composition and one of the best-known in the orchestral repertoire. Initially commissioned by Ida Rubinstein, it became a perfect demonstration of progressive orchestration: only the timbre changes, not the melody or harmony." },
  { q: "Ravel orchestrated a famous work by which composer?", opts: ["Bach", "Mussorgsky — Pictures at an Exhibition, transcribed from the original piano work into an orchestral masterpiece", "Beethoven", "Schubert"], a: 1, fb: "Mussorgsky's Pictures at an Exhibition (1874) was a piano suite. In 1922, Ravel made an orchestration considered one of the most brilliant in the repertoire. He exploits each instrument family to illustrate each picture: saxophone for 'The Old Castle', trumpets for 'The Great Gate of Kiev'." },
  { q: "Debussy's Prélude à l'après-midi d'un faune begins with:", opts: ["A fortissimo brass chord", "An unaccompanied flute solo — chromatic, soft and floating melody", "A timpani rhythm", "A pianissimo string chord"], a: 1, fb: "The work opens with a flute solo — chromatic melody (A4–E4), pianissimo, slow, evocative. This revolutionary opening (1894) illustrates the Impressionist vision: instrumental color (flute = air, light, nature) serves evocation, not motivic development." },
  { q: "Ravel is considered an orchestration genius because:", opts: ["He composed faster than others", "He had exceptional mastery of timbres and instrumental combinations — each instrument in its ideal register, each color in its right place", "He always used all instruments", "He avoided brass"], a: 1, fb: "Ravel had an exceptional sense of instrumental 'placement' — each instrument in its preferred register, each timbre combination calculated for maximum effect. His orchestration of Pictures is a living manual: one can read how he uses each instrument for its specific color." },
  { q: "Ravel lived in what era?", opts: ["Baroque (1600–1750)", "Classicism (1750–1820)", "Late Romanticism / Impressionism (1875–1937)", "Contemporary (after 1950)"], a: 2, fb: "Maurice Ravel (1875–1937) belongs to the musical Impressionism period (with Debussy, his contemporary). He is known for his stylistic precision, sense of humor, piano works (Gaspard de la Nuit) and unmatched orchestration (Bolero, La Valse, Mussorgsky's Pictures)." },
  { q: "The sustain pedal of the piano serves to:", opts: ["Change the key", "Lift the dampers — notes resonate freely, layering and creating harmonic richness and resonance", "Make the sound drier", "Change the register"], a: 1, fb: "The sustain pedal (right pedal) lifts all dampers: strings vibrate freely, including those of unplayed notes (sympathetic resonance). This creates warm resonance and allows connecting harmonies. Used excessively, it creates muddy sound; used with art (Chopin, Debussy), it considerably enriches the timbre." },
  { q: "In standard piano writing, the left hand generally manages:", opts: ["The main melody only", "The bass and harmonic accompaniment — leaving the right hand free for the melody", "Ornaments only", "The high register"], a: 1, fb: "The right hand / left hand division at the piano is fundamental: right hand = melody (medium-high register, approximately C4–C6); left hand = bass + accompaniment (register A0–C4). This division allows a single musician to simultaneously play melody, harmony and bass — a complete ensemble." },
  { q: "Why avoid writing too many notes in the bass register of the piano?", opts: ["By notational convention", "Because the harmonics of bass notes overlap and create muddy sound — close chords in the bass sound blurry", "Because the bass register is reserved for the thumb", "Because bass strings are fewer"], a: 1, fb: "In the bass (C1–C3), harmonics of the notes are numerous and very close. Close chords (C1–D1–E1) create a muddy sound where the notes merge. Solution: wide spacing in the bass (octaves, fifths), closer chords in the medium-high register. Chopin and Ravel master this rule perfectly." },
  { q: "The 'string quartet' formation is composed of:", opts: ["4 violins", "2 violins, 1 viola, 1 cello — the most emblematic chamber music formation", "2 violins, 2 cellos", "Violin, viola, cello, double bass"], a: 1, fb: "The string quartet (2 violins, viola, cello) is the most important chamber formation in the classical repertoire. It covers a wide spectrum (G3–A7 above, C2–G5 below) with a unique timbre homogeneity. Haydn, Mozart, Beethoven and Schubert wrote their most intimate pages for it." },
  { q: "A 'piano trio' is formed of:", opts: ["3 pianos", "Piano, violin, cello — a very common chamber formation in the classical and romantic repertoire", "Piano, flute, clarinet", "Piano, violin, viola"], a: 1, fb: "The piano trio (piano, violin, cello) is one of the most common chamber formations. Beethoven, Schubert, Brahms, Ravel wrote masterpieces for it. Balance is delicate: the piano can easily cover violin and cello if played too loudly." },
  { q: "In chamber music, dynamic balance between musicians is:", opts: ["Managed by a conductor", "The responsibility of each musician — there is no conductor, each person must listen and adapt their volume", "Fixed by the composer with metronomes", "Unimportant — it is a small ensemble"], a: 1, fb: "In chamber music, there is no conductor: balance is the collective responsibility of the musicians. Each must listen to the others and constantly adapt their volume, phrasing and dynamics. It is a form of musical conversation — each instrument is both narrator and listener." },
];

const questionsEs: Question[] = [
  { q: "¿Cuántas grandes familias componen la orquesta sinfónica?", opts: ["2 (cuerdas y metales)", "3 (cuerdas, maderas, metales)", "4 (cuerdas, maderas, metales, percusiones)", "5 (+ piano)"], a: 2, fb: "La orquesta sinfónica tiene 4 familias: cuerdas (violines, violas, violonchelos, contrabajos), maderas (flauta, oboe, clarinete, fagot), metales (trompa, trompeta, trombón, tuba), percusiones (timbales, caja, platillos...). Arpa, piano o guitarra pueden añadirse según la obra." },
  { q: "¿Qué familia forma la 'columna vertebral' de la orquesta?", opts: ["Los metales", "Las percusiones", "Las cuerdas — más numerosas y más presentes", "Las maderas"], a: 2, fb: "Las cuerdas forman la base de la orquesta: son con diferencia las más numerosas (una gran orquesta tiene 60+ cuerdistas de ~100 músicos). Su homogeneidad de timbre permite fundidos y crescendos imposibles con otras familias." },
  { q: "Las 'maderas' se llaman así porque:", opts: ["Tocan músicas de bosque", "Históricamente fabricadas en madera — aunque las flautas y saxofones modernos suelen ser de metal", "Siempre se tocan al aire libre", "Siempre producen un sonido suave"], a: 1, fb: "Las maderas (woodwinds) reciben su nombre por su material histórico. Hoy, las flautas son generalmente de metal (plata, oro) y los saxofones también — pero siguen clasificados en las maderas por su mecanismo de producción de sonido (columna de aire en un tubo)." },
  { q: "¿Cuál es la tesitura práctica del violín?", opts: ["Do2 – Sol4 (registro grave)", "Sol3 – Mi6 aproximadamente (registro soprano)", "Do1 – Do5 (gran extensión)", "La3 – La6 (médium)"], a: 1, fb: "El violín cubre aproximadamente Sol3–Mi6 (con extensiones hasta La7 para los virtuosos). Es el instrumento de melodía soprano por excelencia. Tiene dos atriles: Violín I (melodía principal) y Violín II (armonía alta)." },
  { q: "¿Qué instrumento de cuerda tiene el timbre más oscuro e intermedio?", opts: ["El violín", "La viola", "El violonchelo", "El contrabajo"], a: 1, fb: "La viola tiene un timbre oscuro, cálido y ligeramente nasal — a menudo descrito como el más 'humano' de las cuerdas. Su tesitura intermedia (aproximadamente Do3–La5) y su timbre característico lo convierten en el instrumento de la armonía de contralto y las contra-melodías expresivas." },
  { q: "El violonchelo desempeña qué papel principal en la orquesta?", opts: ["Melodía soprano únicamente", "Melodía grave y bajo cantante — capaz de líneas líricas expresivas en su registro medio", "Acompañamiento rítmico únicamente", "Doblaje de los metales"], a: 1, fb: "El violonchelo es uno de los instrumentos más versátiles: bajo armónico (Do2–Si2), contrapunto (médium) y melodía lírica (Mi3–La5). Su capacidad de cantar en el registro tenor lo ha convertido en favorito para los temas principales (Concierto de Dvorak, Suites de Bach)." },
  { q: "El contrabajo suena a qué altura respecto a la notación?", opts: ["Como está escrito", "Una octava más bajo que lo notado", "Una quinta más bajo", "Una tercera más alto"], a: 1, fb: "El contrabajo es un instrumento transpositor a la octava inferior: lo que se nota como Do3 suena Do2. Esta convención simplifica la lectura (evita demasiadas líneas adicionales). Su papel principal es la base armónica del registro grave." },
  { q: "El 'pizzicato' para cuerdas designa:", opts: ["Tocar con el arco", "Pellizcar las cuerdas con los dedos — técnica percusiva, más breve y seca que el arco", "Tocar muy suavemente", "Tocar con sordina"], a: 1, fb: "El pizzicato consiste en pellizcar las cuerdas (sin arco). Produce un ataque breve y seco — muy usado en acompañamientos de danza, pizzicato de jazz (contrabajo) y efectos de color orquestal. Bartók desarrolló el 'pizzicato snap' (golpeado contra el diapasón)." },
  { q: "El arco (arco) sobre las cuerdas produce:", opts: ["Un sonido breve y seco", "Un sonido continuo — el frotamiento del crin sobre la cuerda crea una vibración sostenida", "Un sonido pulsado", "Un sonido percusivo"], a: 1, fb: "El arco produce un sonido continuo por frotamiento del crin de caballo sobre la cuerda. Esta capacidad de sonido sostenido distingue las cuerdas de los instrumentos de sonidos breves. El détaché, legato, spiccato y col legno (con la madera del arco) son variantes de técnicas de arco." },
  { q: "¿Cuál es el timbre característico de la flauta en registro agudo?", opts: ["Grave y oscuro", "Aéreo, luminoso, brillante — a menudo usado para texturas etéreas", "Nasal y poignante", "Masivo y potente"], a: 1, fb: "En registro agudo, la flauta es luminosa y aérea — ideal para texturas impresionistas (el Preludio a la siesta de un fauno de Debussy comienza con un solo de flauta). En grave (pie de flauta), es velada y misteriosa. Es el instrumento más ágil de las maderas." },
  { q: "¿Qué instrumento de viento es el más expresivo para solos líricos y poignantes?", opts: ["La flauta", "El oboe — su timbre nasal y penetrante lo hace inimitable en melodías expresivas", "El clarinete", "El fagot"], a: 1, fb: "El oboe tiene el timbre más cercano a la voz humana nasal. Tiene un sonido muy distintivo, reconocible incluso mezclado con las cuerdas. Solos célebres: Concierto en La menor de Albinoni, 2º Concierto de Brandeburgo de Bach, 4ª Sinfonía de Brahms." },
  { q: "El clarinete en Sib transpone sus notas a qué altura?", opts: ["Como está escrito", "Un tono más bajo que lo escrito (do suena Sib)", "Un tono más alto", "Una quinta más bajo"], a: 1, fb: "El clarinete en Sib es un instrumento transpositor: lo que se nota como Do suena Sib. Para que el clarinetista toque en Do mayor con las cuerdas, el director le da una parte notada un tono más alto (Re mayor). Esta transposición existe por razones históricas de construcción del instrumento." },
  { q: "Los tres registros del clarinete son:", opts: ["Grave, médium, agudo (uniformes)", "Chalumeau (grave, oscuro), clarinón (médium, claro), agudo (penetrante) — tres colores muy distintos", "Forte, mezzo, piano", "Monódico, armónico, polifónico"], a: 1, fb: "El clarinete tiene tres registros acústicamente muy distintos: chalumeau (grave, La3–Mi4, aterciopelado y oscuro), médium/clarinón (Fa4–Si4, claridad del registro normal), agudo (Do5–Sib6, de brillante a penetrante). Esta heterogeneidad es un desafío y una riqueza para el compositor." },
  { q: "El fagot desempeña qué papel principal en la orquesta?", opts: ["Melodía soprano", "Bajo de las maderas, contrapunto grave y colorista humorístico en agudo", "Solo de fanfarria", "Doblaje de la flauta"], a: 1, fb: "El fagot es el bajo de las maderas y un contrapuntista valioso. En grave (Sib1–Fa2), funda la sección de maderas. En médium, toca líneas de contrapunto. En agudo, su timbre se vuelve ligeramente cómico o lastimero — Dukas lo usa para el aprendiz de brujo, Prokofiev para el abuelo en Pedro y el lobo." },
  { q: "¿Qué instrumento de metal se describe como el 'vínculo' entre metales y maderas?", opts: ["La trompeta", "La trompa (french horn) — su timbre puede fundirse tanto con las maderas como con los metales", "El trombón", "La tuba"], a: 1, fb: "La trompa tiene un timbre único: tocada suavemente (tapada o en armónicos), se funde con las maderas y las cuerdas. Tocada abiertamente fuerte, suena como un metal. Esta versatilidad la convierte en el puente de la orquesta. Brahms la amaba especialmente por sus líneas líricas y sus armonías fundidas." },
  { q: "La trompeta es conocida por:", opts: ["Su timbre grave y noble", "Su brillo y brillantez — cortante en agudo, ideal para fanfarrias y melodías heroicas", "Su suavidad en pianissimo", "Su carácter cómico"], a: 1, fb: "La trompeta es el instrumento de las fanfarrias, los llamamientos militares y las líneas heroicas. Su timbre brillante en forte es incomparable — pero también puede tocar pianissimo con sordina (sonido metálico y lejano). Usada con moderación, marca los momentos clave." },
  { q: "El trombón es el único instrumento de metal que puede:", opts: ["Tocar en pizzicato", "Producir un glissando continuo — gracias a la vara que varía la longitud del tubo", "Tocar 3 partes simultáneamente", "Afinar libremente en tiempo real"], a: 1, fb: "La vara del trombón es única en los metales: al deslizarla, se obtiene un glissando continuo (portamento), imposible en trompeta o trompa. Esta técnica se usa para efectos dramáticos (jazz, Stockhausen) y para pasajes líricos donde la voz humana parece deslizarse de una nota a otra." },
  { q: "¿Por qué la tuba es indispensable en la orquesta?", opts: ["Toca la melodía principal", "Funda la armonía grave de los metales — sin ella, la base de los metales carece de profundidad y asiento", "Reemplaza el contrabajo", "Es únicamente percusiva"], a: 1, fb: "La tuba es la base de los metales: sin ella, los trombones carecen de asiento en el grave. A menudo dobla el contrabajo o toca un bajo independiente. Compuesta de numerosos tubos enrollados, es el instrumento más grave y más potente de los metales." },
  { q: "¿Por qué los metales deben a menudo tocar menos fuerte que su dinámica natural?", opts: ["Por convención musical", "Porque son acústicamente mucho más potentes que las cuerdas y las maderas — tocar fortissimo cubriría completamente las demás secciones", "Porque se cansan rápidamente", "Porque el director siempre lo pide"], a: 1, fb: "La acústica de los metales es radicalmente diferente de la de las cuerdas. Un solo trompetista fortissimo puede cubrir a 30 violinistas forte. El orquestador debe compensar constantemente: nociones de 'piano para los metales' en caso de doblaje con cuerdas, y reservar el fortissimo para tutti de gran potencia." },
  { q: "Los timbales se clasifican como instrumentos de sonido:", opts: ["Indeterminado (como la caja)", "Determinado — se puede ajustar su altura (generalmente entre Do2 y La3)", "Indefinido según la pieza", "Únicamente rítmico"], a: 1, fb: "Los timbales tienen una altura determinada ajustable con pedal: se puede cambiar de nota durante la pieza. Una orquesta generalmente usa 2 a 5 timbales cubriendo aproximadamente Do2–La3. Beethoven les asignó roles melódicos y armónicos precisos (ej. Concierto para violín en Re menor — tensión en Re y La)." },
  { q: "La caja aporta principalmente:", opts: ["Sonidos largos y cantantes", "Una articulación rítmica cortante — redobles, flams, acentuaciones militares", "Armonías graves", "Un color suave e íntimo"], a: 1, fb: "La caja es el instrumento de la precisión rítmica: redobles rápidos, acentos sincopados, figuras militares. Su presencia marca los momentos de energía y articulación. Ravel la usa a lo largo del Boléro para mantener el ritmo ostinato característico." },
  { q: "¿Cuál es la diferencia principal entre las percusiones de sonido determinado e indeterminado?", opts: ["El tamaño del instrumento", "Los instrumentos de sonido determinado tocan alturas precisas (timbales, xilófono, marimba); los indeterminados aportan timbre y ritmo sin altura fija (caja, platillos)", "El material de fabricación", "No hay ninguna diferencia musical"], a: 1, fb: "Distinción fundamental: instrumentos de sonido determinado (timbales, xilófono, vibráfono, marimba, glockenspiel) tocan alturas musicales precisas. Instrumentos de sonido indeterminado (caja, bombo, platillos, tam-tam) aportan color, ritmo y textura." },
  { q: "¿Qué combinación de doblaje produce el sonido más 'fundido' y redondeado?", opts: ["Cuerdas + Metales", "Cuerdas + Maderas — sus timbres se mezclan naturalmente sin que uno domine al otro", "Maderas + Metales", "Percusiones + Cuerdas"], a: 1, fb: "Cuerdas + Maderas forman la combinación de doblaje más suave. Las cuerdas redondean el timbre de las maderas; las maderas precisan la afinación de las cuerdas. Es el doblaje preferido en los pasajes líricos." },
  { q: "El 'doblaje a la octava' (superoctava) produce qué efecto?", opts: ["Ningún cambio sonoro perceptible", "Un approfondissement (octava grave) o un aclaramiento (octava aguda) del sonido — sin cambiar el color armónico", "Un cambio de tonalidad", "Un acorde disonante"], a: 1, fb: "El doblaje a la octava enriquece el timbre: añadir la octava grave (ej. fagot doblando el clarinete) aporta profundidad y calidez; añadir la octava aguda (ej. flauta doblando el violín) aporta brillo y proyección. La armonía no cambia — solo el color del instrumento." },
  { q: "¿Por qué evitar doblar los metales fortissimo sobre las maderas?", opts: ["Por convención estilística únicamente", "Los metales fortissimo cubren completamente las maderas — estas últimas se vuelven inaudibles", "Las maderas suenan mejor solas", "Los metales cambian la tonalidad de las maderas"], a: 1, fb: "La acústica es implacable: un trompetista o trombonista fortissimo produce un volumen sonoro varias veces superior a un oboísta o clarinetista. En doblaje forte, las maderas desaparecen bajo los metales. La solución: los metales tocan mezzo-forte, las maderas forte." },
  { q: "El doblaje al unísono (dos instrumentos, misma altura) sirve para:", opts: ["Cambiar la armonía", "Reforzar la potencia y la proyección sin modificar el carácter melódico ni la armonía", "Crear disonancia", "Transponer una octava"], a: 1, fb: "El doblaje al unísono suma volúmenes sin modificar la armonía ni el carácter. Se usa para reforzar una línea principal (melodía doblada al unísono por varios instrumentos = proyección máxima), o para fusionar los colores de timbre de dos instrumentos diferentes." },
  { q: "Para un pasaje orquestal lírico y suave, ¿qué doblaje es más apropiado?", opts: ["Trompeta + Trombón fortissimo", "Violines + Flautas u oboes — cuerdas + maderas en dinámica suave", "Tuba + Bombo", "Metales tutti"], a: 1, fb: "Para un pasaje suave y lírico, cuerdas + maderas (flauta, oboe, clarinete) en dinámica suave es la combinación ideal. Los timbres se funden naturalmente, el resultado es redondeado y cantante. Los metales se reservan para los clímax o se usan pianissimo con sordina." },
  { q: "En el Boléro de Ravel, la misma melodía y armonía se repiten 18 veces para demostrar:", opts: ["La repetición motívica", "El enriquecimiento orquestal progresivo — cada repetición añade instrumentos, ilustrando cómo la orquestación transforma una idea simple", "La forma rondó", "La sustitución tritónica"], a: 1, fb: "El Boléro (1928) es el estudio de orquestación más famoso del repertorio: misma melodía (en Do mayor), misma armonía, mismo ritmo de caja — solo la orquestación cambia en cada ciclo. Se escucha cada instrumento de la orquesta sucesivamente, luego sus combinaciones cada vez más ricas." },
  { q: "¿Por qué el piano raramente se dobla al unísono en la orquesta?", opts: ["Por convención estilística", "Porque su timbre percusivo y su ataque brusco no se funden naturalmente con las cuerdas y las maderas", "Porque es demasiado suave", "Porque cambia la tonalidad"], a: 1, fb: "El piano tiene un timbre percusivo (envolvente ataque-caída rápida) muy diferente de las cuerdas y las maderas (sonido continuo). En doblaje, este contraste crea un choque en lugar de una fusión. En la orquesta, el piano se usa generalmente como solista (concierto), en color percusivo puntual, o en papel autónomo." },
  { q: "¿Cuál es el instrumento más potente de la orquesta?", opts: ["El bombo", "La trompeta (o los metales en general) — dominan acústicamente todas las demás familias en fortissimo", "El violín (porque es el más numeroso)", "El contrabajo"], a: 1, fb: "Los metales son los instrumentos más potentes de la orquesta, y la trompeta es a menudo la más penetrante. Un solo trompetista fortissimo puede cubrir un atril completo de violines. Esta potencia acústica obliga al orquestador a tratar los metales con moderación para mantener el equilibrio." },
  { q: "¿Cómo equilibra Debussy las texturas en el Preludio a la siesta de un fauno?", opts: ["Usando metales fortissimo", "Manteniendo los metales muy discretos, favoreciendo las texturas ligeras de maderas y cuerdas con pedal de arpa", "Usando solo cuerdas", "Suprimiendo todas las percusiones"], a: 1, fb: "El Preludio a la siesta de un fauno (1894) es un modelo de orquestación impresionista: flauta sola, arpa, cuerdas con sordina, maderas en medias tintas. Debussy usa los metales muy parcamente para mantener la textura transparente — lo contrario de Beethoven o Wagner." },
  { q: "¿Qué registro corresponde a la voz de soprano en la orquesta?", opts: ["Violonchelo y fagot", "Violín I, flauta, oboe, trompeta — instrumentos de tesitura aguda", "Trompa y viola", "Tuba y contrabajo"], a: 1, fb: "El registro soprano (voz alta) está cubierto por: Violín I (Sol3–Mi6), Flauta (Do4–Do7), Oboe (Sib3–La6), Trompeta (Fa#3–Do6). Este registro agudo lleva la melodía principal en la mayoría de las texturas orquestales estándar." },
  { q: "¿Qué registro corresponde a la voz de bajo en la orquesta?", opts: ["Violín II y clarinete", "Contrabajo, tuba, fagot grave — instrumentos de tesitura muy grave", "Viola y trompa", "Trombón y oboe"], a: 1, fb: "El registro bajo está asegurado por: Contrabajo (Mi1–Sol4, suena 8ª más bajo), Tuba (Sib0–Fa4), Fagot grave (Sib1–Mi3), Contrafagot (Sib0–Mi3). Estos instrumentos fundan la pirámide armónica de la orquesta — sin ellos, el sonido carece de asiento." },
  { q: "¿Por qué hay que 'espaciar' las voces en el grave más que en el agudo?", opts: ["Solo por convención", "Porque en el grave, los intervalos estrechos crean barro sonoro — los armónicos se confunden. En el agudo, las terceras y segundas suenan claras", "Porque los instrumentos graves son más grandes", "Porque los armónicos graves son menos numerosos"], a: 1, fb: "Física acústica fundamental: los armónicos de las notas graves son más densos y se superponen más. Un acorde Do2–Mi2 (tercera menor en grave) suena turbio; Do5–Mi5 suena claro. Regla de oro: cuanto más grave, más se espacian las voces (quintas, octavas); en agudo, las segundas y terceras son aceptables." },
  { q: "Un 'agujero armónico' en la orquestación designa:", opts: ["Un silencio en la partitura", "Un registro no cubierto por ningún instrumento — el espectro sonoro tiene una zona vacía, creando un sonido desequilibrado", "Un acorde disminuido", "Una modulación fallida"], a: 1, fb: "Un agujero armónico surge cuando el registro medio no está cubierto mientras el grave y el agudo sí están presentes. El sonido parece 'hueco' — se escucha el bajo y el soprano pero no el medio. Solución: añadir instrumentos en el registro intermedio (viola, clarinete, trompa, violonchelo médium)." },
  { q: "En la correspondencia SATB → orquesta, la voz de tenor (T) está asegurada por:", opts: ["Violín I y flauta", "Violonchelo, trombón, fagot — registro aproximado Do3–Fa4", "Trompa y viola", "Oboe y clarinete"], a: 1, fb: "La voz de tenor corresponde a: Violonchelo (registro médium Do3–Mi5), Trombón (Mi2–Fa4, registro ténor principal), Fagot (registro médium Re3–Mib5). Estos instrumentos aseguran la tercera voz (tenor) en las texturas a 4 partes distribuidas en la orquesta." },
  { q: "Para orquestar un coral a 4 voces (SATB), la voz de soprano se asignará a:", opts: ["Tuba y contrabajo", "Violín I, flauta u oboe — instrumentos cuya tesitura aguda corresponde a la voz soprano", "Fagot y trombón", "Viola y clarinete grave"], a: 1, fb: "Soprano (voz más aguda) → Violín I (Sol3–Mi6), Flauta (Do4–Do7), Oboe (Sib3–La6) o Trompeta. Estos instrumentos tienen el brillo y la tesitura para llevar la línea melódica principal con claridad y proyección." },
  { q: "Ravel es conocido sobre todo por qué obra maestra de orquestación?", opts: ["La Sinfonía n.º 5 en Do menor", "El Boléro — estudio de orquestación progresiva sobre un ostinato rítmico y una melodía repetida 18 veces", "El Réquiem", "La Sinfonía Fantástica"], a: 1, fb: "El Boléro (1928) es la composición más interpretada de Ravel y una de las más conocidas del repertorio orquestal. Concebido inicialmente como un encargo de Ida Rubinstein, se convirtió en una demostración perfecta de la orquestación progresiva: solo cambia el timbre, no la melodía ni la armonía." },
  { q: "Ravel orquestó para orquesta una obra famosa de qué compositor?", opts: ["Bach", "Mussorgsky — Cuadros de una exposición, transcripción del original para piano en obra maestra orquestal", "Beethoven", "Schubert"], a: 1, fb: "Cuadros de una exposición (1874) de Mussorgsky era una suite para piano. En 1922, Ravel hace una orquestación considerada una de las más brillantes del repertorio. Explota cada familia de instrumentos para ilustrar cada cuadro: el saxo para 'El viejo castillo', las trompetas para 'La gran puerta de Kiev'." },
  { q: "El Preludio a la siesta de un fauno de Debussy comienza con:", opts: ["Un acorde fortissimo de metales", "Un solo de flauta no acompañado — melodía cromática, suave y flotante", "Un ritmo de timbales", "Un acorde de cuerdas pianissimo"], a: 1, fb: "La obra se abre con un solo de flauta — melodía cromática (La4–Mi4), pianissimo, lenta, evocadora. Este comienzo revolucionario (1894) ilustra la visión impresionista: el color instrumental (flauta = aire, luz, naturaleza) está al servicio de la evocación, no del desarrollo motivico." },
  { q: "Ravel es considerado un genio de la orquestación porque:", opts: ["Componía más rápido que los demás", "Tenía un dominio excepcional de los timbres y las combinaciones instrumentales — cada instrumento en su registro ideal, cada color en su lugar justo", "Siempre usaba todos los instrumentos", "Evitaba los metales"], a: 1, fb: "Ravel tenía un sentido excepcional de la 'colocación' instrumental — cada instrumento en su registro de predilección, cada combinación de timbres calculada para el efecto máximo. Su orquestación de los Cuadros es un manual viviente: se puede leer cómo usa cada instrumento por su color específico." },
  { q: "Ravel vivía en qué época?", opts: ["Barroco (1600–1750)", "Clasicismo (1750–1820)", "Romanticismo tardío / Impresionismo (1875–1937)", "Contemporáneo (después de 1950)"], a: 2, fb: "Maurice Ravel (1875–1937) pertenece al período del impresionismo musical (con Debussy, su contemporáneo). Es conocido por su precisión estilística, su sentido del humor, sus obras para piano (Gaspard de la Nuit) y su orquestación inigualable (Boléro, La Valse, orquestación de los Cuadros de Mussorgski)." },
  { q: "El pedal de resonancia del piano sirve para:", opts: ["Cambiar la tonalidad", "Levantar los amortiguadores — las notas resuenan libremente, superponiéndose y creando riqueza armónica y de resonancia", "Hacer el sonido más seco", "Cambiar el registro"], a: 1, fb: "El pedal de resonancia (pedal derecho) levanta todos los amortiguadores: las cuerdas vibran libremente, incluidas las de las notas no tocadas (resonancia simpática). Esto crea una resonancia cálida y permite conectar las armonías. Usado con arte (Chopin, Debussy), enriquece considerablemente el timbre." },
  { q: "En la escritura pianística estándar, la mano izquierda gestiona generalmente:", opts: ["Solo la melodía principal", "El bajo y el acompañamiento armónico — dejando la mano derecha libre para la melodía", "Los ornamentos únicamente", "El registro agudo"], a: 1, fb: "La división mano derecha / mano izquierda en el piano es fundamental: mano derecha = melodía (registro médium-agudo, aproximadamente Do4–Do6); mano izquierda = bajo + acompañamiento (registro La0–Do4). Esta división permite a un solo músico tocar simultáneamente melodía, armonía y bajo — un conjunto completo." },
  { q: "¿Por qué hay que evitar escribir demasiadas notas en el grave del piano?", opts: ["Por convención de notación", "Porque los armónicos de las notas graves se superponen y crean barro sonoro — los acordes estrechos en grave suenan borrosos", "Porque el registro grave está reservado al pulgar", "Porque las cuerdas graves son menos numerosas"], a: 1, fb: "En el grave (Do1–Do3), los armónicos de las notas son numerosos y muy cercanos. Los acordes estrechos (Do1–Re1–Mi1) crean un barro sonoro donde las notas se confunden. Solución: espaciado amplio en grave (octavas, quintas), acordes más estrechos en médium-agudo. Chopin y Ravel dominan perfectamente esta regla." },
  { q: "La formación 'cuarteto de cuerdas' está compuesta de:", opts: ["4 violines", "2 violines, 1 viola, 1 violonchelo — la formación de cámara más emblemática", "2 violines, 2 violonchelos", "Violín, viola, violonchelo, contrabajo"], a: 1, fb: "El cuarteto de cuerdas (2 violines, viola, violonchelo) es la formación de cámara más importante del repertorio clásico. Cubre un amplio espectro (Sol3–La7 arriba, Do2–Sol5 abajo) con una homogeneidad de timbre única. Haydn, Mozart, Beethoven y Schubert escribieron sus páginas más íntimas para él." },
  { q: "Un 'trío con piano' (piano trio) está formado por:", opts: ["3 pianos", "Piano, violín, violonchelo — formación de cámara muy frecuente en el repertorio clásico y romántico", "Piano, flauta, clarinete", "Piano, violín, viola"], a: 1, fb: "El trío con piano (piano, violín, violonchelo) es una de las formaciones de cámara más frecuentes. Beethoven, Schubert, Brahms, Ravel han escrito obras maestras para él. El equilibrio es delicado: el piano puede fácilmente cubrir el violín y el violonchelo si toca demasiado fuerte." },
  { q: "En música de cámara, el equilibrio dinámico entre músicos es:", opts: ["Gestionado por un director de orquesta", "La responsabilidad de cada músico — no hay director, cada uno debe escuchar y adaptar su volumen", "Fijado por el compositor con metrónomos", "No importante — es una pequeña formación"], a: 1, fb: "En música de cámara, no hay director: el equilibrio es la responsabilidad colectiva de los músicos. Cada uno debe escuchar a los demás y adaptar permanentemente su volumen, su fraseo y su dinámica. Es una forma de conversación musical — cada instrumento es a la vez narrador y oyente." },
];

const questionsDe: Question[] = [
  { q: "Aus wie vielen großen Familien besteht das Sinfonieorchester?", opts: ["2 (Streicher und Blechbläser)", "3 (Streicher, Holzbläser, Blechbläser)", "4 (Streicher, Holzbläser, Blechbläser, Schlagzeug)", "5 (+ Klavier)"], a: 2, fb: "Das Sinfonieorchester hat 4 Familien: Streicher (Violinen, Bratschen, Celli, Kontrabässe), Holzbläser (Flöte, Oboe, Klarinette, Fagott), Blechbläser (Horn, Trompete, Posaune, Tuba), Schlagzeug (Pauken, kleine Trommel, Becken...). Harfe, Klavier oder Gitarre können je nach Werk hinzugefügt werden." },
  { q: "Welche Familie bildet das 'Rückgrat' des Orchesters?", opts: ["Die Blechbläser", "Das Schlagzeug", "Die Streicher — zahlreichste und am konstantesten präsente Familie", "Die Holzbläser"], a: 2, fb: "Die Streicher bilden das Fundament des Orchesters: Sie sind bei weitem die zahlreichsten (ein großes Orchester hat 60+ Streicher von ~100 Musikern). Ihre Klangfarben-Homogenität ermöglicht Blends und Crescendi, die mit anderen Familien unmöglich sind." },
  { q: "Holzbläser heißen so, weil:", opts: ["Sie Waldmusik spielen", "Sie historisch aus Holz gefertigt wurden — obwohl moderne Flöten und Saxophone oft aus Metall bestehen", "Sie immer im Freien gespielt werden", "Sie immer einen weichen Klang erzeugen"], a: 1, fb: "Holzbläser sind nach ihrem historischen Material benannt. Heute bestehen Flöten üblicherweise aus Metall (Silber, Gold) und Saxophone ebenfalls — sie bleiben aber als Holzbläser klassifiziert, wegen ihres Klangerzeugungsmechanismus (Luftsäule in einem Rohr)." },
  { q: "Was ist der praktische Tonumfang der Violine?", opts: ["C2 – G4 (tiefer Register)", "G3 – E6 ungefähr (Sopranregister)", "C1 – C5 (großer Umfang)", "A3 – A6 (medium)"], a: 1, fb: "Die Violine umfasst etwa G3–E6 (mit Erweiterungen bis A7 für Virtuosen). Sie ist das Sopranmelodie-Instrument par excellence. Es gibt zwei Pulte: Violine I (Hauptmelodie) und Violine II (hohe Harmonie)." },
  { q: "Welches Streichinstrument hat die dunkelste und mittlere Klangfarbe?", opts: ["Die Violine", "Die Bratsche (Viola)", "Das Cello", "Der Kontrabass"], a: 1, fb: "Die Bratsche hat eine dunkle, warme und leicht nasale Klangfarbe — oft als das 'menschlichste' der Streichinstrumente beschrieben. Ihr mittlerer Tonumfang (ungefähr C3–A5) und ihre charakteristische Klangfarbe machen sie zum Instrument der Alt-Harmonie und expressiver Gegenmelodien." },
  { q: "Das Cello spielt welche Hauptrolle im Orchester?", opts: ["Nur Sopranmelodie", "Tiefe Melodie und singender Bass — fähig zu expressiven lyrischen Linien in seinem mittleren Register", "Nur rhythmische Begleitung", "Verdoppelung der Blechbläser"], a: 1, fb: "Das Cello ist eines der vielseitigsten Instrumente: harmonischer Bass (C2–B2), Kontrapunkt (Medium) und lyrische Melodie (E3–A5). Seine Fähigkeit, im Tenorregister zu singen, hat es zum Liebling für Hauptthemen gemacht (Dvořák Konzert, Bach Suiten)." },
  { q: "Der Kontrabass klingt in welcher Höhe im Vergleich zur Notation?", opts: ["Wie geschrieben", "Eine Oktave tiefer als notiert", "Eine Quinte tiefer", "Eine Terz höher"], a: 1, fb: "Der Kontrabass ist ein transponierendes Instrument in der unteren Oktave: was als C3 notiert ist, klingt als C2. Diese Konvention vereinfacht das Lesen (vermeidet zu viele Hilfslinien). Seine Hauptrolle ist das harmonische Fundament des tiefen Registers." },
  { q: "'Pizzicato' bei Streichern bezeichnet:", opts: ["Mit dem Bogen spielen", "Die Saiten mit den Fingern zupfen — eine perkussive Technik, kürzer und trockener als der Bogen", "Sehr leise spielen", "Mit Dämpfer spielen"], a: 1, fb: "Pizzicato bedeutet Zupfen der Saiten (ohne Bogen). Es erzeugt einen kurzen, trockenen Anschlag — weit verbreitet in Tanzbegleitungen, Jazz-Pizzicato (Kontrabass) und Orchesterfarben-Effekten. Bartók entwickelte das 'Snap-Pizzicato' (an das Griffbrett geschlagen)." },
  { q: "Der Bogen (arco) auf den Streichern erzeugt:", opts: ["Einen kurzen, trockenen Klang", "Einen kontinuierlichen Klang — die Reibung des Rosshaarbogens auf der Saite erzeugt anhaltende Vibration", "Einen gezupften Klang", "Einen perkussiven Klang"], a: 1, fb: "Der Bogen erzeugt durch Reibung von Rosshaar auf der Saite einen Dauerton. Diese Fähigkeit zu gehaltenem Klang unterscheidet die Streicher von Instrumenten mit kurzem Anschlag. Détaché, Legato, Spiccato und col legno (mit dem Holz des Bogens) sind Varianten der Bogentechnik." },
  { q: "Was ist die charakteristische Klangfarbe der Flöte im hohen Register?", opts: ["Dunkel und tief", "Luftig, leuchtend, brillant — oft für ätherische Texturen verwendet", "Nasal und eindringlich", "Massiv und kraftvoll"], a: 1, fb: "Im hohen Register ist die Flöte leuchtend und luftig — ideal für impressionistische Texturen (Debussys Prélude à l'après-midi d'un faune beginnt mit einem Flötensolo). Im tiefen Register (Fußstück) ist sie verschleiert und geheimnisvoll. Sie ist das agilste der Holzblasinstrumente." },
  { q: "Welches Blasinstrument ist für lyrische und eindringliche Soli am ausdrucksstärksten?", opts: ["Die Flöte", "Die Oboe — ihre nasale und durchdringende Klangfarbe macht sie in expressiven Melodien unvergleichbar", "Die Klarinette", "Das Fagott"], a: 1, fb: "Die Oboe hat die der nasalen menschlichen Stimme am nächsten kommende Klangfarbe. Sie hat einen sehr markanten Klang, erkennbar auch gemischt mit Streichern. Berühmte Soli: Albinonis Konzert in a-Moll, Bachs Brandenburgisches Konzert Nr. 2, Brahms' 4. Sinfonie." },
  { q: "Die B-Klarinette transponiert ihre Noten in welche Höhe?", opts: ["Wie geschrieben", "Einen Ton tiefer als geschrieben (C klingt als B)", "Einen Ton höher", "Eine Quinte tiefer"], a: 1, fb: "Die B-Klarinette ist ein transponierendes Instrument: was als C notiert ist, klingt als B. Damit der Klarinettist mit den Streichern in C-Dur spielt, bekommt er eine einen Ton höher notierte Stimme (D-Dur). Diese Transposition existiert aus historischen Gründen des Instrumentenbaus." },
  { q: "Die drei Register der Klarinette sind:", opts: ["Tief, mittel, hoch (gleichförmig)", "Chalumeau (tief, dunkel), Clarino (mittel, hell), hoch (durchdringend) — drei sehr unterschiedliche Farben", "Forte, mezzo, piano", "Monodisch, harmonisch, polyphon"], a: 1, fb: "Die Klarinette hat drei akustisch sehr unterschiedliche Register: Chalumeau (tief, A3–E4, samtig und dunkel), Mittel-/Clarinino-Register (F4–B4, Klarheit des Normalregisters), hoch (C5–Bb6, von brillant bis durchdringend). Diese Heterogenität ist Herausforderung und Reichtum für den Komponisten." },
  { q: "Das Fagott spielt welche Hauptrolle im Orchester?", opts: ["Sopranmelodie", "Bass der Holzbläser, Bassgegenstimmen und humoristischer Kolorist im hohen Register", "Fanfarensolo", "Verdoppelung der Flöte"], a: 1, fb: "Das Fagott ist der Bass der Holzbläser und ein wertvoller Kontrapunktist. Im Bass (Bb1–F2) gründet es die Holzbläsersektion. Im mittleren Register spielt es Gegenstimmen. Im hohen Register wird seine Klangfarbe leicht komisch oder klagend — Dukas nutzt es für den Zauberlehrling, Prokofjew für den Großvater in Peter und der Wolf." },
  { q: "Welches Blechblasinstrument wird als 'Bindeglied' zwischen Blechbläsern und Holzbläsern beschrieben?", opts: ["Die Trompete", "Das Horn (french horn) — seine Klangfarbe kann sich sowohl mit Holzbläsern als auch mit Blechbläsern verbinden", "Die Posaune", "Die Tuba"], a: 1, fb: "Das Horn hat eine einzigartige Klangfarbe: leise gespielt (gedämpft oder in Obertönen) verbindet es sich mit Holzbläsern und Streichern. Offen laut gespielt klingt es wie ein Blechbläser. Diese Vielseitigkeit macht es zum Bindeglied des Orchesters. Brahms schätzte es besonders für seine lyrischen Linien." },
  { q: "Die Trompete ist bekannt für:", opts: ["Ihre tiefe und edle Klangfarbe", "Ihren Glanz und ihre Brillanz — schneidend im hohen Register, ideal für Fanfaren und heroische Melodien", "Ihre Sanftheit im Pianissimo", "Ihren komischen Charakter"], a: 1, fb: "Die Trompete ist das Instrument der Fanfaren, militärischen Rufe und heroischen Linien. Ihre brillante Fortissimo-Klangfarbe ist unvergleichlich — aber sie kann auch pianissimo mit Dämpfer spielen (metallischer, ferner Klang). Sparsam eingesetzt markiert sie Schlüsselmomente." },
  { q: "Die Posaune ist das einzige Blechblasinstrument, das:", opts: ["Pizzicato spielen kann", "Einen kontinuierlichen Glissando erzeugen kann — dank der Zugstange, die die Rohrlänge verändert", "3 Stimmen gleichzeitig spielen kann", "Sich in Echtzeit frei stimmen kann"], a: 1, fb: "Die Zugstange der Posaune ist einzigartig unter den Blechbläsern: beim Herausziehen entsteht ein kontinuierliches Glissando (Portamento), auf Trompete oder Horn unmöglich. Diese Technik wird für dramatische Effekte (Jazz, Stockhausen) und lyrische Passagen verwendet." },
  { q: "Warum ist die Tuba im Orchester unverzichtbar?", opts: ["Sie spielt die Hauptmelodie", "Sie gründet die Bassharmonie der Blechbläser — ohne sie fehlt der Blechbläserbasis Tiefe und Fundament", "Sie ersetzt den Kontrabass", "Sie ist nur perkussiv"], a: 1, fb: "Die Tuba ist das Fundament der Blechbläser: ohne sie fehlt den Posaunen das Fundament im Bass. Sie verdoppelt oft den Kontrabass oder spielt einen eigenständigen Bass. Aus vielen verschlungenen Rohren bestehend, ist sie das tiefste und lauteste Blechblasinstrument." },
  { q: "Warum müssen Blechbläser oft leiser spielen als ihre natürliche Dynamik?", opts: ["Aus musikalischer Konvention", "Weil sie akustisch viel lauter sind als Streicher und Holzbläser — Fortissimo würde die anderen Sektionen völlig überdecken", "Weil sie schnell ermüden", "Weil der Dirigent es immer fordert"], a: 1, fb: "Die Akustik der Blechbläser unterscheidet sich radikal von der der Streicher. Ein einzelner Trompeter fortissimo kann 30 forte Violinisten überdecken. Der Orchestrator muss ständig kompensieren: 'Piano für die Blechbläser' bei Verdoppelung mit Streichern, und Fortissimo den großen Tutti-Momenten vorbehalten." },
  { q: "Pauken werden als Instrumente mit welchem Klang klassifiziert?", opts: ["Unbestimmter Höhe (wie kleine Trommel)", "Bestimmter Höhe — ihre Stimmung kann eingestellt werden (generell zwischen C2 und A3)", "Undefinierter Höhe je nach Stück", "Nur rhythmischer Funktion"], a: 1, fb: "Pauken haben eine bestimmte, pedalverstellbare Höhe: Die Note kann während des Stückes geändert werden. Ein Orchester verwendet generell 2 bis 5 Pauken, die ungefähr C2–A3 abdecken. Beethoven wies ihnen präzise melodische und harmonische Rollen zu (z.B. Violinkonzert d-Moll — Spannung auf D und A)." },
  { q: "Die kleine Trommel bringt hauptsächlich:", opts: ["Lange, singende Klänge", "Scharfe rhythmische Artikulation — Wirbel, Flams, militärische Akzente", "Tiefe Harmonien", "Eine weiche, intime Farbe"], a: 1, fb: "Die kleine Trommel ist das Instrument der rhythmischen Präzision: schnelle Wirbel, synkopierte Akzente, militärische Figuren. Ihre Präsenz markiert Momente der Energie und Artikulation. Ravel verwendet sie im Boléro, um den charakteristischen Ostinato-Rhythmus aufrechtzuerhalten." },
  { q: "Was ist der Hauptunterschied zwischen bestimmtem und unbestimmtem Schlagzeug?", opts: ["Die Größe des Instruments", "Bestimmte Instrumente spielen präzise Tonhöhen (Pauken, Xylophon, Marimba); unbestimmte bringen Klangfarbe und Rhythmus ohne feste Höhe (kleine Trommel, Becken)", "Das Herstellungsmaterial", "Es gibt keinen musikalischen Unterschied"], a: 1, fb: "Grundlegende Unterscheidung: Instrumente mit bestimmter Höhe (Pauken, Xylophon, Vibraphon, Marimba, Glockenspiel) spielen präzise Tonhöhen. Instrumente mit unbestimmter Höhe (kleine Trommel, große Trommel, Becken, Tamtam) bringen Farbe, Rhythmus und Textur." },
  { q: "Welche Verdoppelungskombination erzeugt den 'verschmolzensten' und rundsten Klang?", opts: ["Streicher + Blechbläser", "Streicher + Holzbläser — ihre Klangfarben mischen sich natürlich ohne dass eine dominiert", "Holzbläser + Blechbläser", "Schlagzeug + Streicher"], a: 1, fb: "Streicher + Holzbläser bilden die weichste Verdoppelungskombination. Die Streicher runden die Holzbläser-Klangfarbe ab; die Holzbläser präzisieren die Intonation der Streicher. Dies ist die bevorzugte Verdoppelung in lyrischen Passagen." },
  { q: "Die 'Oktavverdoppelung' (Superoktave) erzeugt welchen Effekt?", opts: ["Keine wahrnehmbare Klangveränderung", "Eine Vertiefung (tiefe Oktave) oder Aufhellung (hohe Oktave) des Klanges — ohne die harmonische Farbe zu ändern", "Einen Tonartenwechsel", "Einen Dissonanzakkord"], a: 1, fb: "Oktavverdoppelung bereichert die Klangfarbe: Das Hinzufügen der tiefen Oktave (z.B. Fagott verdoppelt die Klarinette) bringt Tiefe und Wärme; das Hinzufügen der hohen Oktave (z.B. Flöte verdoppelt die Violine) bringt Brillanz und Projektion. Die Harmonie ändert sich nicht — nur die Instrumentalfarbe." },
  { q: "Warum sollte man Blechbläser fortissimo nicht über Holzbläser verdoppeln?", opts: ["Nur aus stilistischer Konvention", "Blechbläser fortissimo überdecken die Holzbläser völlig — diese werden unhörbar", "Holzbläser klingen allein besser", "Blechbläser ändern die Tonart der Holzbläser"], a: 1, fb: "Die Akustik ist gnadenlos: ein Trompeter oder Posaunist fortissimo erzeugt ein Klangvolumen, das vielfach größer ist als das eines Oboisten oder Klarinettisten. Bei starker Verdoppelung verschwinden die Holzbläser unter den Blechbläsern. Lösung: Blechbläser spielen mezzoforte, Holzbläser forte." },
  { q: "Die Unisono-Verdoppelung (zwei Instrumente, gleiche Höhe) dient dazu:", opts: ["Die Harmonie zu ändern", "Die Kraft und Projektion zu verstärken, ohne den melodischen Charakter oder die Harmonie zu modifizieren", "Dissonanz zu erzeugen", "Um eine Oktave zu transponieren"], a: 1, fb: "Unisono-Verdoppelung addiert Lautstärken, ohne Harmonie oder Charakter zu modifizieren. Sie dient zur Verstärkung einer Hauptlinie (Melodie im Unisono von mehreren Instrumenten verdoppelt = maximale Projektion), oder zur Verschmelzung der Klangfarben zweier verschiedener Instrumente." },
  { q: "Für eine lyrische und weiche Orchesterpassage, welche Verdoppelung ist am besten geeignet?", opts: ["Trompete + Posaune fortissimo", "Violinen + Flöten oder Oboe — Streicher + Holzbläser in weicher Dynamik", "Tuba + große Trommel", "Blechbläser tutti"], a: 1, fb: "Für eine weiche und lyrische Passage ist Streicher + Holzbläser (Flöte, Oboe, Klarinette) in weicher Dynamik die ideale Kombination. Die Klangfarben verbinden sich natürlich, das Ergebnis ist rund und singend. Blechbläser sind für Höhepunkte reserviert oder pianissimo mit Dämpfer für eine ferne Farbe." },
  { q: "In Ravels Boléro werden dieselbe Melodie und Harmonie 18 Mal wiederholt, um zu demonstrieren:", opts: ["Motivische Wiederholung", "Progressive orchestrale Bereicherung — jede Wiederholung fügt Instrumente hinzu und zeigt, wie Orchestrierung eine einfache Idee transformiert", "Rondoform", "Tritonussubstitution"], a: 1, fb: "Der Boléro (1928) ist die bekannteste Orchestrierungsstudie des Repertoires: gleiche Melodie (in C-Dur), gleiche Harmonie, gleicher Kleiner-Trommel-Rhythmus — nur die Orchestrierung ändert sich in jedem Zyklus. Man hört nacheinander jedes Instrument des Orchesters, dann in immer reicheren Kombinationen." },
  { q: "Warum wird das Klavier im Orchester selten im Unisono verdoppelt?", opts: ["Aus stilistischer Konvention", "Weil seine perkussive Klangfarbe und sein abrupter Anschlag sich nicht natürlich mit Streichern und Holzbläsern verbinden", "Weil es zu leise ist", "Weil es die Tonart ändert"], a: 1, fb: "Das Klavier hat eine perkussive Klangfarbe (schnelle Hüllkurve Attack-Decay) sehr verschieden von Streichern und Holzbläsern (Dauerton). Bei Verdoppelung erzeugt dieser Kontrast einen Clash statt einer Fusion. Im Orchester wird das Klavier generell als Solist (Konzert), als punktuelle perkussive Farbe oder in autonomer Rolle verwendet." },
  { q: "Welches Instrument ist das lauteste im Orchester?", opts: ["Die große Trommel", "Die Trompete (oder die Blechbläser allgemein) — sie dominieren akustisch alle anderen Familien im Fortissimo", "Die Violine (weil sie am zahlreichsten ist)", "Der Kontrabass"], a: 1, fb: "Blechbläser sind die lautesten Instrumente des Orchesters, und die Trompete ist oft die durchdringendste. Ein einzelner Trompeter fortissimo kann ein vollständiges Streicher-Pult überdecken. Diese akustische Macht verlangt vom Orchestrator, Blechbläser sparsam einzusetzen." },
  { q: "Wie balanciert Debussy die Texturen im Prélude à l'après-midi d'un faune?", opts: ["Indem er Blechbläser fortissimo einsetzt", "Indem er die Blechbläser sehr diskret hält und leichte Holzbläser- und Streichertexturen mit Harfenpedal bevorzugt", "Indem er nur Streicher verwendet", "Indem er alle Schlagzeuge entfernt"], a: 1, fb: "Das Prélude à l'après-midi d'un faune (1894) ist ein Modell impressionistischer Orchestrierung: Flötensolo, Harfe, gedämpfte Streicher, Holzbläser in Halbtönen. Debussy setzt Blechbläser sehr sparsam ein, um die Textur transparent zu halten — das Gegenteil von Beethoven oder Wagner." },
  { q: "Welches Register entspricht der Sopranstimme im Orchester?", opts: ["Cello und Fagott", "Violine I, Flöte, Oboe, Trompete — Instrumente mit hohem Tonumfang", "Horn und Bratsche", "Tuba und Kontrabass"], a: 1, fb: "Das Sopranregister (hohe Stimme) wird abgedeckt durch: Violine I (G3–E6), Flöte (C4–C7), Oboe (Bb3–A6), Trompete (F#3–C6). Dieses hohe Register trägt in den meisten Orchestertexturen die Hauptmelodie." },
  { q: "Welches Register entspricht der Bassstimme im Orchester?", opts: ["Violine II und Klarinette", "Kontrabass, Tuba, Bass-Fagott — Instrumente mit sehr tiefem Tonumfang", "Bratsche und Horn", "Posaune und Oboe"], a: 1, fb: "Das Bassregister wird abgedeckt durch: Kontrabass (E1–G4, klingt 8va tiefer), Tuba (Bb0–F4), Fagott-Bass (Bb1–E3), Kontrafagott (Bb0–E3). Diese Instrumente gründen die harmonische Pyramide des Orchesters — ohne sie fehlt dem Klang das Fundament." },
  { q: "Warum müssen Stimmen im Bass weiter 'gespreizt' werden als im Diskant?", opts: ["Nur aus Konvention", "Weil im Bass enge Intervalle Schlamm erzeugen — Obertöne überlappen sich. Im Diskant klingen Terzen und Sekunden klar", "Weil Bassinstrumente größer sind", "Weil es im Bass weniger Obertöne gibt"], a: 1, fb: "Grundlegende Akustikphysik: Obertöne von Bassnoten sind dichter und überlappen sich stärker. Ein Akkord C2–E2 (kleine Terz im Bass) klingt schlammig; C5–E5 klingt klar. Goldene Regel: je tiefer, desto weiter die Stimmen spreizen (Quinten, Oktaven); im Diskant sind Sekunden und Terzen akzeptabel." },
  { q: "Eine 'harmonische Lücke' in der Orchestrierung bezeichnet:", opts: ["Eine Pause in der Partitur", "Ein Register, das von keinem Instrument abgedeckt wird — das Klangspektrum hat eine leere Zone, die einen unausgewogenen Klang erzeugt", "Einen verminderten Akkord", "Eine misslungene Modulation"], a: 1, fb: "Eine harmonische Lücke entsteht, wenn das mittlere Register nicht abgedeckt ist, während Bass und Diskant präsent sind. Der Klang wirkt 'hohl' — man hört den Bass und den Sopran, aber nicht die Mitte. Lösung: Instrumente im Zwischenregister hinzufügen (Bratsche, Klarinette, Horn, mittleres Cello)." },
  { q: "In der SATB → Orchester-Entsprechung wird die Tenorstimme (T) abgedeckt durch:", opts: ["Violine I und Flöte", "Cello, Posaune, Fagott — ungefähr Register C3–F4", "Horn und Bratsche", "Oboe und Klarinette"], a: 1, fb: "Die Tenorstimme entspricht: Cello (mittleres Register C3–E5), Posaune (E2–F4, Haupttenorregister), Fagott (mittleres Register D3–Eb5). Diese Instrumente übernehmen die dritte Stimme (Tenor) in vierstimmigen Texturen, die im Orchester verteilt sind." },
  { q: "Um einen vierstimmigen Choral (SATB) zu orchestrieren, wird die Sopranstimme gegeben an:", opts: ["Tuba und Kontrabass", "Violine I, Flöte oder Oboe — Instrumente, deren hoher Tonumfang der Sopranstimme entspricht", "Fagott und Posaune", "Bratsche und Bassklarinette"], a: 1, fb: "Sopran (höchste Stimme) → Violine I (G3–E6), Flöte (C4–C7), Oboe (Bb3–A6) oder Trompete. Diese Instrumente haben die Brillanz und den Tonumfang, um die Hauptmelodie mit Klarheit und Projektion zu tragen." },
  { q: "Ravel ist vor allem für welches Meisterwerk der Orchestrierung berühmt?", opts: ["Sinfonie Nr. 5 in c-Moll", "Der Boléro — eine progressive Orchestrierungsstudie über ein rhythmisches Ostinato und eine 18 Mal wiederholte Melodie", "Das Requiem", "Symphonie fantastique"], a: 1, fb: "Der Boléro (1928) ist Ravels meistgespielte Komposition und eine der bekanntesten im Orchesterrepertoire. Ursprünglich auf Bestellung von Ida Rubinstein komponiert, wurde er eine perfekte Demonstration progressiver Orchestrierung: nur die Klangfarbe ändert sich, nicht Melodie oder Harmonie." },
  { q: "Ravel orchestrierte ein berühmtes Werk von welchem Komponisten?", opts: ["Bach", "Mussorgsky — Bilder einer Ausstellung, Transkription des Klavieroriginals in ein orchestrales Meisterwerk", "Beethoven", "Schubert"], a: 1, fb: "Mussorgskys Bilder einer Ausstellung (1874) war eine Klaviersuite. 1922 machte Ravel eine Orchestrierung, die als eine der brillantesten des Repertoires gilt. Er nutzt jede Instrumentenfamilie, um jedes Bild zu illustrieren: Saxophon für 'Das alte Schloss', Trompeten für 'Das Große Tor von Kiew'." },
  { q: "Debussys Prélude à l'après-midi d'un faune beginnt mit:", opts: ["Einem Blechbläser-Fortissimo-Akkord", "Einem unbegleiteten Flötensolo — chromatische, weiche und schwebende Melodie", "Einem Pauken-Rhythmus", "Einem Streicher-Pianissimo-Akkord"], a: 1, fb: "Das Werk öffnet mit einem Flötensolo — chromatische Melodie (A4–E4), pianissimo, langsam, evokativ. Dieser revolutionäre Beginn (1894) illustriert die impressionistische Vision: Instrumentalfarbe (Flöte = Luft, Licht, Natur) dient der Evokation, nicht der motivischen Entwicklung." },
  { q: "Ravel gilt als Orchestrierungsgenie, weil:", opts: ["Er schneller als andere komponierte", "Er eine außergewöhnliche Beherrschung der Klangfarben und Instrumentalkombinationen hatte — jedes Instrument in seinem idealen Register, jede Farbe an ihrem richtigen Platz", "Er immer alle Instrumente verwendete", "Er Blechbläser mied"], a: 1, fb: "Ravel hatte ein außergewöhnliches Gespür für die instrumentale 'Platzierung' — jedes Instrument in seinem bevorzugten Register, jede Klangfarbenkombination für maximalen Effekt berechnet. Seine Orchestrierung der Bilder ist ein lebendiges Handbuch: man kann ablesen, wie er jedes Instrument für seine spezifische Farbe einsetzt." },
  { q: "Ravel lebte in welcher Epoche?", opts: ["Barock (1600–1750)", "Klassik (1750–1820)", "Spätromantik / Impressionismus (1875–1937)", "Zeitgenössisch (nach 1950)"], a: 2, fb: "Maurice Ravel (1875–1937) gehört zur Periode des musikalischen Impressionismus (mit Debussy, seinem Zeitgenossen). Er ist bekannt für seine stilistische Präzision, seinen Humor, seine Klavierwerke (Gaspard de la Nuit) und seine unübertroffene Orchestrierung (Boléro, La Valse, Mussorgskys Bilder)." },
  { q: "Das Haltepedal des Klaviers dient dazu:", opts: ["Die Tonart zu ändern", "Die Dämpfer zu heben — Noten klingen frei nach, überlagern sich und schaffen harmonischen Reichtum und Resonanz", "Den Klang trockener zu machen", "Das Register zu ändern"], a: 1, fb: "Das Haltepedal (rechtes Pedal) hebt alle Dämpfer: Saiten schwingen frei, auch die nicht gespielter Noten (sympathische Resonanz). Dies erzeugt warme Resonanz und ermöglicht das Verbinden von Harmonien. Kunstvoll eingesetzt (Chopin, Debussy) bereichert es die Klangfarbe erheblich." },
  { q: "In der Standard-Klaviernotation verwaltet die linke Hand generell:", opts: ["Nur die Hauptmelodie", "Den Bass und die harmonische Begleitung — die rechte Hand bleibt frei für die Melodie", "Nur Ornamente", "Das hohe Register"], a: 1, fb: "Die rechte/linke Hand-Aufteilung am Klavier ist fundamental: rechte Hand = Melodie (mittel-hohes Register, ungefähr C4–C6); linke Hand = Bass + Begleitung (Register A0–C4). Diese Aufteilung erlaubt einem einzigen Musiker, gleichzeitig Melodie, Harmonie und Bass zu spielen — ein vollständiges Ensemble." },
  { q: "Warum sollte man im Bassregister des Klaviers nicht zu viele Noten schreiben?", opts: ["Aus Notationskonvention", "Weil sich Obertöne von Bassnoten überlagern und Klangschlamm erzeugen — enge Akkorde im Bass klingen verschwommen", "Weil das Bassregister für den Daumen reserviert ist", "Weil es weniger Basssaiten gibt"], a: 1, fb: "Im Bass (C1–C3) sind Obertöne der Noten zahlreich und sehr nahe. Enge Akkorde (C1–D1–E1) erzeugen einen Klangschlamm, in dem Noten verschwimmen. Lösung: weite Abstände im Bass (Oktaven, Quinten), engere Akkorde im mittleren bis hohen Register. Chopin und Ravel beherrschen diese Regel perfekt." },
  { q: "Die 'Streichquartett'-Formation besteht aus:", opts: ["4 Violinen", "2 Violinen, 1 Bratsche, 1 Cello — die emblematischste Kammermusikformation", "2 Violinen, 2 Celli", "Violine, Bratsche, Cello, Kontrabass"], a: 1, fb: "Das Streichquartett (2 Violinen, Bratsche, Cello) ist die wichtigste Kammerformation des klassischen Repertoires. Es deckt ein weites Spektrum ab (G3–A7 oben, C2–G5 unten) mit einzigartiger Klangfarben-Homogenität. Haydn, Mozart, Beethoven und Schubert schrieben ihre intimsten Seiten dafür." },
  { q: "Ein 'Klaviertrio' (piano trio) besteht aus:", opts: ["3 Klavieren", "Klavier, Violine, Cello — eine im klassischen und romantischen Repertoire sehr häufige Kammerformation", "Klavier, Flöte, Klarinette", "Klavier, Violine, Bratsche"], a: 1, fb: "Das Klaviertrio (Klavier, Violine, Cello) ist eine der häufigsten Kammerformationen. Beethoven, Schubert, Brahms, Ravel schrieben Meisterwerke dafür. Die Balance ist heikel: Das Klavier kann Violine und Cello leicht überdecken, wenn es zu laut spielt." },
  { q: "In der Kammermusik ist das dynamische Gleichgewicht zwischen den Musikern:", opts: ["Von einem Dirigenten geregelt", "Die Verantwortung jedes Musikers — es gibt keinen Dirigenten, jeder muss zuhören und seine Lautstärke anpassen", "Vom Komponisten mit Metronomen festgelegt", "Unwichtig — es ist eine kleine Formation"], a: 1, fb: "In der Kammermusik gibt es keinen Dirigenten: das Gleichgewicht ist die kollektive Verantwortung der Musiker. Jeder muss den anderen zuhören und ständig seine Lautstärke, seine Phrasierung und seine Dynamik anpassen. Es ist eine Form des musikalischen Gesprächs — jedes Instrument ist gleichzeitig Erzähler und Zuhörer." },
];

const questionsIt: Question[] = [
  { q: "Quante grandi famiglie compongono l'orchestra sinfonica?", opts: ["2 (archi e ottoni)", "3 (archi, legni, ottoni)", "4 (archi, legni, ottoni, percussioni)", "5 (+ pianoforte)"], a: 2, fb: "L'orchestra sinfonica ha 4 famiglie: archi (violini, viole, violoncelli, contrabbassi), legni (flauto, oboe, clarinetto, fagotto), ottoni (corno, tromba, trombone, tuba), percussioni (timpani, rullante, piatti...). Arpa, pianoforte o chitarra possono essere aggiunti a seconda dell'opera." },
  { q: "Quale famiglia forma la 'spina dorsale' dell'orchestra?", opts: ["Gli ottoni", "Le percussioni", "Gli archi — più numerosi e più costantemente presenti", "I legni"], a: 2, fb: "Gli archi formano il fondamento dell'orchestra: sono di gran lunga i più numerosi (un'orchestra grande ha 60+ archi su ~100 musicisti). La loro omogeneità di timbro permette blend e crescendo impossibili con altre famiglie." },
  { q: "I 'legni' si chiamano così perché:", opts: ["Suonano musiche di foresta", "Storicamente fabbricati in legno — anche se flauti e sassofoni moderni sono spesso in metallo", "Si suonano sempre all'aperto", "Producono sempre un suono morbido"], a: 1, fb: "I legni (woodwinds) devono il loro nome al loro materiale storico. Oggi i flauti sono generalmente in metallo (argento, oro) e i sassofoni anche — ma rimangono classificati tra i legni per il loro meccanismo di produzione del suono (colonna d'aria in un tubo)." },
  { q: "Qual è la tessitura pratica del violino?", opts: ["Do2 – Sol4 (registro grave)", "Sol3 – Mi6 circa (registro soprano)", "Do1 – Do5 (grande estensione)", "La3 – La6 (medio)"], a: 1, fb: "Il violino copre approssimativamente Sol3–Mi6 (con estensioni fino a La7 per i virtuosi). È lo strumento di melodia soprano per eccellenza. Esistono due parti: Violino I (melodia principale) e Violino II (armonia alta)." },
  { q: "Quale strumento ad arco ha il timbro più scuro e intermedio?", opts: ["Il violino", "La viola", "Il violoncello", "Il contrabbasso"], a: 1, fb: "La viola ha un timbro scuro, caldo e leggermente nasale — spesso descritto come il più 'umano' degli archi. La sua tessitura intermedia (circa Do3–La5) e il suo timbro caratteristico la rendono lo strumento dell'armonia contralto e delle contro-melodie espressive." },
  { q: "Il violoncello svolge quale ruolo principale nell'orchestra?", opts: ["Solo melodia soprano", "Melodia grave e basso cantante — capace di linee liriche espressive nel suo registro medio", "Solo accompagnamento ritmico", "Raddoppio degli ottoni"], a: 1, fb: "Il violoncello è uno degli strumenti più versatili: basso armonico (Do2–Si2), contrappunto (medio) e melodia lirica (Mi3–La5). La sua capacità di cantare nel registro tenore lo ha reso favorito per i temi principali (Concerto di Dvořák, Suite di Bach)." },
  { q: "Il contrabbasso suona a quale altezza rispetto alla notazione?", opts: ["Come scritto", "Un'ottava più basso del notato", "Una quinta più basso", "Una terza più alto"], a: 1, fb: "Il contrabbasso è uno strumento traspositori all'ottava inferiore: ciò che è notato Do3 suona Do2. Questa convenzione semplifica la lettura (evita troppe righe aggiuntive). Il suo ruolo principale è il fondamento armonico del registro grave." },
  { q: "Il 'pizzicato' per gli archi designa:", opts: ["Suonare con l'arco", "Pizzicare le corde con le dita — tecnica percussiva, più breve e secca dell'arco", "Suonare molto piano", "Suonare con la sordina"], a: 1, fb: "Il pizzicato consiste nel pizzicare le corde (senza arco). Produce un attacco breve e secco — molto usato negli accompagnamenti di danza, nel pizzicato jazz (contrabbasso) e negli effetti di colore orchestrale. Bartók sviluppò il 'pizzicato snap' (schioccato contro la tastiera)." },
  { q: "L'arco (arco) sugli archi produce:", opts: ["Un suono breve e secco", "Un suono continuo — l'attrito del crine sulla corda crea una vibrazione sostenuta", "Un suono pizzicato", "Un suono percussivo"], a: 1, fb: "L'arco produce un suono continuo per attrito di crini di cavallo sulla corda. Questa capacità di suono tenuto distingue gli archi dagli strumenti a suoni brevi. Il détaché, legato, spiccato e col legno (con il legno dell'arco) sono varianti delle tecniche d'arco." },
  { q: "Qual è il timbro caratteristico del flauto nel registro acuto?", opts: ["Grave e scuro", "Aereo, luminoso, brillante — spesso usato per texture eteree", "Nasale e penetrante", "Massiccio e potente"], a: 1, fb: "Nel registro acuto, il flauto è luminoso e aereo — ideale per le texture impressioniste (il Prélude à l'après-midi d'un faune di Debussy inizia con un assolo di flauto). Nel grave (piede del flauto), è velato e misterioso. È lo strumento più agile dei legni." },
  { q: "Quale strumento a fiato è il più espressivo per soli lirici e penetranti?", opts: ["Il flauto", "L'oboe — il suo timbro nasale e penetrante lo rende inimitabile nelle melodie espressive", "Il clarinetto", "Il fagotto"], a: 1, fb: "L'oboe ha il timbro più vicino alla voce umana nasale. Ha un suono molto distintivo, riconoscibile anche mescolato con gli archi. Assoli famosi: Concerto in La minore di Albinoni, 2° Concerto Brandeburghese di Bach, 4ª Sinfonia di Brahms." },
  { q: "Il clarinetto in Sib trasporta le sue note a quale altezza?", opts: ["Come scritto", "Un tono più basso del scritto (do suona Sib)", "Un tono più alto", "Una quinta più basso"], a: 1, fb: "Il clarinetto in Sib è uno strumento traspositori: ciò che è notato Do suona Sib. Perché il clarinettista suoni in Do maggiore con gli archi, il direttore gli dà una parte notata un tono più alto (Re maggiore). Questa trasposizione esiste per ragioni storiche di costruzione dello strumento." },
  { q: "I tre registri del clarinetto sono:", opts: ["Grave, medio, acuto (uniformi)", "Chalumeau (grave, scuro), clarinetto (medio, chiaro), acuto (penetrante) — tre colori molto distinti", "Forte, mezzo, piano", "Monodico, armonico, polifonico"], a: 1, fb: "Il clarinetto ha tre registri acusticamente molto distinti: chalumeau (grave, La3–Mi4, vellutato e scuro), medio/clarinetto (Fa4–Si4, chiarezza del registro normale), acuto (Do5–Sib6, da brillante a penetrante). Questa eterogeneità è sfida e ricchezza per il compositore." },
  { q: "Il fagotto svolge quale ruolo principale nell'orchestra?", opts: ["Melodia soprano", "Basso dei legni, contrappunto grave e colorista umoristico nell'acuto", "Assolo di fanfara", "Raddoppio del flauto"], a: 1, fb: "Il fagotto è il basso dei legni e un prezioso contrappuntista. Nel grave (Sib1–Fa2), fonda la sezione dei legni. Nel medio, suona linee di contrappunto. Nell'acuto, il suo timbro diventa leggermente comico o lamentoso — Dukas lo usa per l'apprendista stregone, Prokofiev per il nonno in Pietro e il Lupo." },
  { q: "Quale ottone è descritto come il 'collegamento' tra ottoni e legni?", opts: ["La tromba", "Il corno (french horn) — il suo timbro può fondersi tanto con i legni quanto con gli ottoni", "Il trombone", "La tuba"], a: 1, fb: "Il corno ha un timbro unico: suonato piano (chiuso o in armonici), si fonde con legni e archi. Suonato apertamente forte, suona come un ottone. Questa versatilità lo rende il ponte dell'orchestra. Brahms lo amava particolarmente per le sue linee liriche e le sue armonie fuse." },
  { q: "La tromba è conosciuta per:", opts: ["Il suo timbro grave e nobile", "Il suo splendore e la sua brillantezza — tagliente nell'acuto, ideale per fanfare e melodie eroiche", "La sua dolcezza in pianissimo", "Il suo carattere comico"], a: 1, fb: "La tromba è lo strumento delle fanfare, degli appelli militari e delle linee eroiche. Il suo timbro brillante in forte è incomparabile — ma può anche suonare pianissimo con la sordina (suono metallico e lontano). Usata con parsimonia, segna i momenti chiave." },
  { q: "Il trombone è l'unico ottone che può:", opts: ["Suonare in pizzicato", "Produrre un glissando continuo — grazie alla coulisse che varia la lunghezza del tubo", "Suonare 3 parti contemporaneamente", "Accordarsi liberamente in tempo reale"], a: 1, fb: "La coulisse del trombone è unica tra gli ottoni: facendola scorrere si ottiene un glissando continuo (portamento), impossibile su tromba o corno. Questa tecnica è usata per effetti drammatici (jazz, Stockhausen) e per passaggi lirici dove la voce umana sembra scivolare da una nota all'altra." },
  { q: "Perché la tuba è indispensabile nell'orchestra?", opts: ["Suona la melodia principale", "Fonda l'armonia grave degli ottoni — senza di essa, la base degli ottoni manca di profondità e di assise", "Sostituisce il contrabbasso", "È solo percussiva"], a: 1, fb: "La tuba è il fondamento degli ottoni: senza di essa, i tromboni mancano di assise nel grave. Spesso raddoppia il contrabbasso o suona un basso indipendente. Composta di numerosi tubi avvolti, è lo strumento più grave e più potente degli ottoni." },
  { q: "Perché gli ottoni devono spesso suonare meno forte della loro dinamica naturale?", opts: ["Per convenzione musicale", "Perché sono acusticamente molto più potenti degli archi e dei legni — suonare fortissimo coprirebbe completamente le altre sezioni", "Perché si stancano rapidamente", "Perché il direttore lo chiede sempre"], a: 1, fb: "L'acustica degli ottoni è radicalmente diversa da quella degli archi. Un solo trombettista fortissimo può coprire 30 violinisti forte. L'orchestratore deve costantemente compensare: 'piano per gli ottoni' in caso di raddoppio con gli archi, e riservare il fortissimo ai tutti di grande potenza." },
  { q: "I timpani sono classificati come strumenti di suono:", opts: ["Indeterminato (come il rullante)", "Determinato — si può regolare la loro altezza (generalmente tra Do2 e La3)", "Indefinito secondo il brano", "Solo ritmico"], a: 1, fb: "I timpani hanno un'altezza determinata regolabile con un pedale: si può cambiare nota durante il brano. Un'orchestra usa generalmente da 2 a 5 timpani che coprono approssimativamente Do2–La3. Beethoven assegnò loro ruoli melodici e armonici precisi (es. Concerto per violino in Re minore — tensione su Re e La)." },
  { q: "Il rullante apporta principalmente:", opts: ["Suoni lunghi e cantanti", "Un'articolazione ritmica tagliente — rulli, flam, accentuazioni militari", "Armonie gravi", "Un colore morbido e intimo"], a: 1, fb: "Il rullante è lo strumento della precisione ritmica: rulli rapidi, accenti sincopati, figure militari. La sua presenza segna i momenti di energia e articolazione. Ravel lo usa lungo tutto il Boléro per mantenere il ritmo ostinato caratteristico." },
  { q: "Qual è la differenza principale tra percussioni a suono determinato e indeterminato?", opts: ["La dimensione dello strumento", "Gli strumenti a suono determinato suonano altezze precise (timpani, silofono, marimba); gli indeterminati apportano timbro e ritmo senza altezza fissa (rullante, piatti)", "Il materiale di fabbricazione", "Non c'è nessuna differenza musicale"], a: 1, fb: "Distinzione fondamentale: strumenti a suono determinato (timpani, silofono, vibrafono, marimba, glockenspiel) suonano altezze musicali precise. Strumenti a suono indeterminato (rullante, gran cassa, piatti, tam-tam) apportano colore, ritmo e texture." },
  { q: "Quale combinazione di raddoppio produce il suono più 'fuso' e arrotondato?", opts: ["Archi + Ottoni", "Archi + Legni — i loro timbri si mescolano naturalmente senza che uno domini l'altro", "Legni + Ottoni", "Percussioni + Archi"], a: 1, fb: "Archi + Legni formano la combinazione di raddoppio più morbida. Gli archi arrotondano il timbro dei legni; i legni precisano l'intonazione degli archi. È il raddoppio preferito nei passaggi lirici." },
  { q: "Il 'raddoppio all'ottava' (superottava) produce quale effetto?", opts: ["Nessun cambiamento sonoro percepibile", "Un approfondimento (ottava grave) o un schiarimento (ottava acuta) del suono — senza cambiare il colore armonico", "Un cambio di tonalità", "Un accordo dissonante"], a: 1, fb: "Il raddoppio all'ottava arricchisce il timbro: aggiungere l'ottava grave (es. fagotto che raddoppia il clarinetto) porta profondità e calore; aggiungere l'ottava acuta (es. flauto che raddoppia il violino) porta brillantezza e proiezione. L'armonia non cambia — solo il colore dello strumento." },
  { q: "Perché evitare di raddoppiare gli ottoni fortissimo sui legni?", opts: ["Solo per convenzione stilistica", "Gli ottoni fortissimo coprono completamente i legni — questi ultimi diventano inudibili", "I legni suonano meglio da soli", "Gli ottoni cambiano la tonalità dei legni"], a: 1, fb: "L'acustica è spietata: un trombettista o trombonista fortissimo produce un volume sonoro molte volte superiore a un oboista o clarinettista. In caso di raddoppio forte, i legni scompaiono sotto gli ottoni. La soluzione: gli ottoni suonano mezzaforte, i legni forte." },
  { q: "Il raddoppio all'unisono (due strumenti, stessa altezza) serve a:", opts: ["Cambiare l'armonia", "Rinforzare la potenza e la proiezione senza modificare il carattere melodico né l'armonia", "Creare dissonanza", "Trasporre di un'ottava"], a: 1, fb: "Il raddoppio all'unisono somma volumi senza modificare armonia né carattere. Viene usato per rinforzare una linea principale (melodia raddoppiata all'unisono da più strumenti = proiezione massima), o per fondere i colori di timbro di due strumenti diversi." },
  { q: "Per un passaggio orchestrale lirico e morbido, quale raddoppio è più appropriato?", opts: ["Tromba + Trombone fortissimo", "Violini + Flauti o oboe — archi + legni in dinamica morbida", "Tuba + Gran cassa", "Ottoni tutti"], a: 1, fb: "Per un passaggio morbido e lirico, archi + legni (flauto, oboe, clarinetto) in dinamica morbida è la combinazione ideale. I timbri si fondono naturalmente, il risultato è arrotondato e cantante. Gli ottoni sono riservati ai climax o usati pianissimo con sordina." },
  { q: "Nel Boléro di Ravel, la stessa melodia e armonia si ripetono 18 volte per dimostrare:", opts: ["La ripetizione motivica", "L'arricchimento orchestrale progressivo — ogni ripetizione aggiunge strumenti, illustrando come l'orchestrazione trasformi un'idea semplice", "La forma rondò", "La sostituzione del tritono"], a: 1, fb: "Il Boléro (1928) è il più famoso studio di orchestrazione del repertorio: stessa melodia (in Do maggiore), stessa armonia, stesso ritmo di rullante — solo l'orchestrazione cambia a ogni ciclo. Si ascoltano successivamente tutti gli strumenti dell'orchestra, poi le loro combinazioni sempre più ricche." },
  { q: "Perché il pianoforte viene raramente raddoppiato all'unisono nell'orchestra?", opts: ["Per convenzione stilistica", "Perché il suo timbro percussivo e il suo attacco brusco non si fondono naturalmente con archi e legni", "Perché è troppo morbido", "Perché cambia la tonalità"], a: 1, fb: "Il pianoforte ha un timbro percussivo (inviluppo attacco-decadimento rapido) molto diverso dagli archi e dai legni (suono continuo). In caso di raddoppio, questo contrasto crea uno scontro invece di una fusione. Nell'orchestra, il pianoforte è generalmente usato come solista (concerto), in colore percussivo puntuale, o in ruolo autonomo." },
  { q: "Qual è lo strumento più potente dell'orchestra?", opts: ["La gran cassa", "La tromba (o gli ottoni in generale) — dominano acusticamente tutte le altre famiglie in fortissimo", "Il violino (perché è il più numeroso)", "Il contrabbasso"], a: 1, fb: "Gli ottoni sono gli strumenti più potenti dell'orchestra, e la tromba è spesso la più penetrante. Un solo trombettista fortissimo può coprire un'intera sezione di violini. Questa potenza acustica impone all'orchestratore di trattare gli ottoni con parsimonia." },
  { q: "Come Debussy bilancia le texture nel Prélude à l'après-midi d'un faune?", opts: ["Usando gli ottoni fortissimo", "Mantenendo gli ottoni molto discreti, favorendo le texture leggere di legni e archi con pedale d'arpa", "Usando solo archi", "Sopprimendo tutte le percussioni"], a: 1, fb: "Il Prélude à l'après-midi d'un faune (1894) è un modello di orchestrazione impressionista: flauto solo, arpa, archi con sordina, legni in mezze tinte. Debussy usa gli ottoni molto parcamente per mantenere la texture trasparente — l'opposto di Beethoven o Wagner." },
  { q: "Quale registro corrisponde alla voce di soprano nell'orchestra?", opts: ["Violoncello e fagotto", "Violino I, flauto, oboe, tromba — strumenti di tessitura acuta", "Corno e viola", "Tuba e contrabbasso"], a: 1, fb: "Il registro soprano (voce alta) è coperto da: Violino I (Sol3–Mi6), Flauto (Do4–Do7), Oboe (Sib3–La6), Tromba (Fa#3–Do6). Questo registro acuto porta la melodia principale nella maggior parte delle texture orchestrali standard." },
  { q: "Quale registro corrisponde alla voce di basso nell'orchestra?", opts: ["Violino II e clarinetto", "Contrabbasso, tuba, fagotto grave — strumenti di tessitura molto grave", "Viola e corno", "Trombone e oboe"], a: 1, fb: "Il registro basso è assicurato da: Contrabbasso (Mi1–Sol4, suona 8va più basso), Tuba (Sib0–Fa4), Fagotto grave (Sib1–Mi3), Controfagotto (Sib0–Mi3). Questi strumenti fondano la piramide armonica dell'orchestra — senza di loro, il suono manca di assise." },
  { q: "Perché bisogna 'spaziare' le voci nel grave più che nell'acuto?", opts: ["Solo per convenzione", "Perché nel grave, gli intervalli stretti creano fango sonoro — le armoniche si confondono. Nell'acuto, le terze e le seconde suonano chiare", "Perché gli strumenti gravi sono più grandi", "Perché le armoniche gravi sono meno numerose"], a: 1, fb: "Fisica acustica fondamentale: le armoniche delle note gravi sono più dense e si sovrappongono di più. Un accordo Do2–Mi2 (terza minore nel grave) suona fangoso; Do5–Mi5 suona chiaro. Regola d'oro: più si va nel grave, più si spaziamo le voci (quinte, ottave); nell'acuto, le seconde e le terze sono accettabili." },
  { q: "Un 'buco armonico' nell'orchestrazione designa:", opts: ["Un silenzio nella partitura", "Un registro non coperto da nessuno strumento — lo spettro sonoro ha una zona vuota, creando un suono squilibrato", "Un accordo diminuito", "Una modulazione mancata"], a: 1, fb: "Un buco armonico si verifica quando il registro medio non è coperto mentre il grave e l'acuto sono presenti. Il suono sembra 'vuoto' — si sente il basso e il soprano ma non il mezzo. Soluzione: aggiungere strumenti nel registro intermedio (viola, clarinetto, corno, violoncello medio)." },
  { q: "Nella corrispondenza SATB → orchestra, la voce di tenore (T) è assicurata da:", opts: ["Violino I e flauto", "Violoncello, trombone, fagotto — registro approssimativo Do3–Fa4", "Corno e viola", "Oboe e clarinetto"], a: 1, fb: "La voce di tenore corrisponde a: Violoncello (registro medio Do3–Mi5), Trombone (Mi2–Fa4, registro tenore principale), Fagotto (registro medio Re3–Mib5). Questi strumenti assicurano la terza voce (tenore) nelle texture a 4 parti distribuite nell'orchestra." },
  { q: "Per orchestrare un corale a 4 voci (SATB), la voce di soprano viene assegnata a:", opts: ["Tuba e contrabbasso", "Violino I, flauto o oboe — strumenti la cui tessitura acuta corrisponde alla voce soprano", "Fagotto e trombone", "Viola e clarinetto basso"], a: 1, fb: "Soprano (voce più acuta) → Violino I (Sol3–Mi6), Flauto (Do4–Do7), Oboe (Sib3–La6) o Tromba. Questi strumenti hanno la brillantezza e la tessitura per portare la linea melodica principale con chiarezza e proiezione." },
  { q: "Ravel è famoso soprattutto per quale capolavoro di orchestrazione?", opts: ["La Sinfonia n.5 in Do minore", "Il Boléro — studio di orchestrazione progressiva su un ostinato ritmico e una melodia ripetuta 18 volte", "Il Requiem", "La Sinfonia Fantastica"], a: 1, fb: "Il Boléro (1928) è la composizione più eseguita di Ravel e una delle più note del repertorio orchestrale. Concepito inizialmente su commissione di Ida Rubinstein, è diventato una dimostrazione perfetta dell'orchestrazione progressiva: solo il timbro cambia, non la melodia né l'armonia." },
  { q: "Ravel orchestrò per orchestra un'opera famosa di quale compositore?", opts: ["Bach", "Mussorgsky — Quadri di un'esposizione, trascrizione dell'originale per pianoforte in capolavoro orchestrale", "Beethoven", "Schubert"], a: 1, fb: "Quadri di un'esposizione (1874) di Musorgsky era una suite per pianoforte. Nel 1922, Ravel ne fa un'orchestrazione considerata tra le più brillanti del repertorio. Sfrutta ogni famiglia di strumenti per illustrare ogni quadro: il sassofono per 'Il vecchio castello', le trombe per 'La Grande porta di Kiev'." },
  { q: "Il Prélude à l'après-midi d'un faune di Debussy inizia con:", opts: ["Un accordo fortissimo di ottoni", "Un assolo di flauto non accompagnato — melodia cromatica, morbida e fluttuante", "Un ritmo di timpani", "Un accordo di archi pianissimo"], a: 1, fb: "L'opera si apre con un assolo di flauto — melodia cromatica (La4–Mi4), pianissimo, lenta, evocativa. Questo inizio rivoluzionario (1894) illustra la visione impressionista: il colore strumentale (flauto = aria, luce, natura) è al servizio dell'evocazione, non dello sviluppo motivico." },
  { q: "Ravel è considerato un genio dell'orchestrazione perché:", opts: ["Componeva più velocemente degli altri", "Aveva una padronanza eccezionale dei timbri e delle combinazioni strumentali — ogni strumento nel suo registro ideale, ogni colore al suo posto giusto", "Usava sempre tutti gli strumenti", "Evitava gli ottoni"], a: 1, fb: "Ravel aveva un senso eccezionale del 'posizionamento' strumentale — ogni strumento nel suo registro di predilezione, ogni combinazione di timbri calcolata per l'effetto massimo. La sua orchestrazione dei Quadri è un manuale vivente: si può leggere come usa ogni strumento per il suo colore specifico." },
  { q: "Ravel viveva in quale epoca?", opts: ["Barocco (1600–1750)", "Classicismo (1750–1820)", "Romanticismo tardivo / Impressionismo (1875–1937)", "Contemporaneo (dopo il 1950)"], a: 2, fb: "Maurice Ravel (1875–1937) appartiene al periodo dell'impressionismo musicale (con Debussy, suo contemporaneo). È noto per la sua precisione stilistica, il suo senso dell'umorismo, le sue opere per pianoforte (Gaspard de la Nuit) e la sua orchestrazione ineguagliata (Boléro, La Valse, orchestrazione dei Quadri di Musorgsky)." },
  { q: "Il pedale di risonanza del pianoforte serve a:", opts: ["Cambiare la tonalità", "Sollevare gli smorzatori — le note risuonano liberamente, sovrapponendosi e creando ricchezza armonica e risonanza", "Rendere il suono più secco", "Cambiare il registro"], a: 1, fb: "Il pedale di risonanza (pedale destro) solleva tutti gli smorzatori: le corde vibrano liberamente, comprese quelle delle note non suonate (risonanza per simpatia). Questo crea una risonanza calda e permette di collegare le armonie. Usato con arte (Chopin, Debussy), arricchisce notevolmente il timbro." },
  { q: "Nella scrittura pianistica standard, la mano sinistra gestisce generalmente:", opts: ["Solo la melodia principale", "Il basso e l'accompagnamento armonico — lasciando la mano destra libera per la melodia", "Solo gli abbellimenti", "Il registro acuto"], a: 1, fb: "La divisione mano destra / mano sinistra al pianoforte è fondamentale: mano destra = melodia (registro medio-acuto, circa Do4–Do6); mano sinistra = basso + accompagnamento (registro La0–Do4). Questa divisione permette a un solo musicista di suonare contemporaneamente melodia, armonia e basso." },
  { q: "Perché bisogna evitare di scrivere troppe note nel grave del pianoforte?", opts: ["Per convenzione di notazione", "Perché le armoniche delle note gravi si sovrappongono e creano fango sonoro — gli accordi stretti nel grave suonano confusi", "Perché il registro grave è riservato al pollice", "Perché le corde gravi sono meno numerose"], a: 1, fb: "Nel grave (Do1–Do3), le armoniche delle note sono numerose e molto vicine. Accordi stretti (Do1–Re1–Mi1) creano un fango sonoro in cui le note si confondono. Soluzione: ampia spaziatura nel grave (ottave, quinte), accordi più stretti nel medio-acuto. Chopin e Ravel padroneggiano perfettamente questa regola." },
  { q: "La formazione 'quartetto d'archi' è composta da:", opts: ["4 violini", "2 violini, 1 viola, 1 violoncello — la formazione cameristica più emblematica", "2 violini, 2 violoncelli", "Violino, viola, violoncello, contrabbasso"], a: 1, fb: "Il quartetto d'archi (2 violini, viola, violoncello) è la formazione cameristica più importante del repertorio classico. Copre un ampio spettro (Sol3–La7 in alto, Do2–Sol5 in basso) con una omogeneità di timbro unica. Haydn, Mozart, Beethoven e Schubert vi hanno scritto le loro pagine più intime." },
  { q: "Un 'trio con pianoforte' (piano trio) è formato da:", opts: ["3 pianoforti", "Pianoforte, violino, violoncello — formazione cameristica molto frequente nel repertorio classico e romantico", "Pianoforte, flauto, clarinetto", "Pianoforte, violino, viola"], a: 1, fb: "Il trio con pianoforte (pianoforte, violino, violoncello) è una delle formazioni cameristiche più frequenti. Beethoven, Schubert, Brahms, Ravel vi hanno scritto capolavori. L'equilibrio è delicato: il pianoforte può facilmente coprire violino e violoncello se suona troppo forte." },
  { q: "In musica da camera, l'equilibrio dinamico tra i musicisti è:", opts: ["Gestito da un direttore d'orchestra", "La responsabilità di ogni musicista — non c'è un direttore, ognuno deve ascoltare e adattare il proprio volume", "Fissato dal compositore con i metronomi", "Non importante — è una piccola formazione"], a: 1, fb: "In musica da camera non c'è un direttore: l'equilibrio è la responsabilità collettiva dei musicisti. Ognuno deve ascoltare gli altri e adattare continuamente il proprio volume, il proprio fraseggio e la propria dinamica. È una forma di conversazione musicale — ogni strumento è allo stesso tempo narratore e ascoltatore." },
];

const questionsPt: Question[] = [
  { q: "Quantas grandes famílias compõem a orquestra sinfónica?", opts: ["2 (cordas e metais)", "3 (cordas, madeiras, metais)", "4 (cordas, madeiras, metais, percussões)", "5 (+ piano)"], a: 2, fb: "A orquestra sinfónica tem 4 famílias: cordas (violinos, violas, violoncelos, contrabaixos), madeiras (flauta, oboé, clarinete, fagote), metais (trompa, trompete, trombone, tuba), percussões (tímpanos, caixa, pratos...). Harpa, piano ou guitarra podem ser adicionados consoante a obra." },
  { q: "Qual família forma a 'espinha dorsal' da orquestra?", opts: ["Os metais", "As percussões", "As cordas — mais numerosas e mais constantemente presentes", "As madeiras"], a: 2, fb: "As cordas formam o fundamento da orquestra: são de longe as mais numerosas (uma grande orquestra tem 60+ cordas de ~100 músicos). A sua homogeneidade de timbre permite blends e crescendos impossíveis com outras famílias." },
  { q: "As 'madeiras' chamam-se assim porque:", opts: ["Tocam músicas de floresta", "Historicamente fabricadas em madeira — embora flautas e saxofones modernos sejam frequentemente em metal", "Tocam sempre ao ar livre", "Produzem sempre um som suave"], a: 1, fb: "As madeiras (woodwinds) devem o seu nome ao seu material histórico. Hoje, as flautas são geralmente em metal (prata, ouro) e os saxofones também — mas continuam classificados nas madeiras pelo seu mecanismo de produção de som (coluna de ar num tubo)." },
  { q: "Qual é a tessitura prática do violino?", opts: ["Dó2 – Sol4 (registo grave)", "Sol3 – Mi6 aproximadamente (registo soprano)", "Dó1 – Dó5 (grande extensão)", "Lá3 – Lá6 (médio)"], a: 1, fb: "O violino cobre aproximadamente Sol3–Mi6 (com extensões até Lá7 para os virtuosos). É o instrumento de melodia soprano por excelência. Tem dois naipes: Violino I (melodia principal) e Violino II (harmonia alta)." },
  { q: "Qual instrumento de cordas tem o timbre mais escuro e intermédio?", opts: ["O violino", "A viola", "O violoncelo", "O contrabaixo"], a: 1, fb: "A viola tem um timbre escuro, quente e ligeiramente nasal — frequentemente descrito como o mais 'humano' das cordas. A sua tessitura intermédia (aproximadamente Dó3–Lá5) e o seu timbre característico fazem dela o instrumento da harmonia de contralto e das contra-melodias expressivas." },
  { q: "O violoncelo desempenha que papel principal na orquestra?", opts: ["Apenas melodia soprano", "Melodia grave e baixo cantante — capaz de linhas líricas expressivas no seu registo médio", "Apenas acompanhamento rítmico", "Dobramento dos metais"], a: 1, fb: "O violoncelo é um dos instrumentos mais versáteis: baixo harmónico (Dó2–Si2), contraponto (médio) e melodia lírica (Mi3–Lá5). A sua capacidade de cantar no registo de tenor tornou-o favorito para os temas principais (Concerto de Dvořák, Suites de Bach)." },
  { q: "O contrabaixo soa a que altura em relação à notação?", opts: ["Como escrito", "Uma oitava mais baixo do que o notado", "Uma quinta mais baixo", "Uma terça mais alto"], a: 1, fb: "O contrabaixo é um instrumento transpositor à oitava inferior: o que é notado como Dó3 soa Dó2. Esta convenção simplifica a leitura (evita demasiadas linhas suplementares). O seu papel principal é o fundamento harmónico do registo grave." },
  { q: "O 'pizzicato' para cordas designa:", opts: ["Tocar com o arco", "Dedilhar as cordas com os dedos — técnica percussiva, mais curta e seca do que o arco", "Tocar muito suavemente", "Tocar com surdina"], a: 1, fb: "O pizzicato consiste em dedilhar as cordas (sem arco). Produz um ataque breve e seco — muito usado nos acompanhamentos de dança, no pizzicato de jazz (contrabaixo) e nos efeitos de cor orquestral. Bartók desenvolveu o 'pizzicato snap' (estalado contra o braço)." },
  { q: "O arco (arco) sobre as cordas produz:", opts: ["Um som breve e seco", "Um som contínuo — o atrito do cerdame na corda cria uma vibração sustentada", "Um som dedilhado", "Um som percussivo"], a: 1, fb: "O arco produz um som contínuo por atrito do cerdame de crina de cavalo na corda. Esta capacidade de som sustentado distingue as cordas dos instrumentos de sons breves. O détaché, legato, spiccato e col legno (com a madeira do arco) são variantes de técnicas de arco." },
  { q: "Qual é o timbre característico da flauta no registo agudo?", opts: ["Grave e escuro", "Aéreo, luminoso, brilhante — frequentemente usado para texturas etéreas", "Nasal e penetrante", "Massivo e poderoso"], a: 1, fb: "No registo agudo, a flauta é luminosa e aérea — ideal para texturas impressionistas (o Prélude à l'après-midi d'un faune de Debussy começa com um solo de flauta). No grave (pé da flauta), é velada e misteriosa. É o instrumento mais ágil das madeiras." },
  { q: "Qual instrumento de sopro é o mais expressivo para solos líricos e penetrantes?", opts: ["A flauta", "O oboé — o seu timbre nasal e penetrante torna-o inimitável nas melodias expressivas", "O clarinete", "O fagote"], a: 1, fb: "O oboé tem o timbre mais próximo da voz humana nasal. Tem um som muito distintivo, reconhecível mesmo misturado com cordas. Solos famosos: Concerto em Lá menor de Albinoni, 2.º Concerto de Brandeburgo de Bach, 4.ª Sinfonia de Brahms." },
  { q: "O clarinete em Sib transpõe as suas notas a que altura?", opts: ["Como escrito", "Um tom mais baixo do que escrito (dó soa Sib)", "Um tom mais alto", "Uma quinta mais baixo"], a: 1, fb: "O clarinete em Sib é um instrumento transpositor: o que é notado como Dó soa Sib. Para que o clarinetista toque em Dó maior com as cordas, o maestro dá-lhe uma parte notada um tom mais alto (Ré maior). Esta transposição existe por razões históricas de construção do instrumento." },
  { q: "Os três registos do clarinete são:", opts: ["Grave, médio, agudo (uniformes)", "Chalumeau (grave, escuro), clarinete (médio, claro), agudo (penetrante) — três cores muito distintas", "Forte, mezzo, piano", "Monódico, harmónico, polifónico"], a: 1, fb: "O clarinete tem três registos acusticamente muito distintos: chalumeau (grave, Lá3–Mi4, aveludado e escuro), médio/clarinete (Fá4–Si4, clareza do registo normal), agudo (Dó5–Sib6, de brilhante a penetrante). Esta heterogeneidade é desafio e riqueza para o compositor." },
  { q: "O fagote desempenha que papel principal na orquestra?", opts: ["Melodia soprano", "Baixo das madeiras, contraponto grave e colorista humorístico no agudo", "Solo de fanfarra", "Dobramento da flauta"], a: 1, fb: "O fagote é o baixo das madeiras e um valioso contrapuntista. No grave (Sib1–Fá2), funda a secção das madeiras. No médio, toca linhas de contraponto. No agudo, o seu timbre torna-se ligeiramente cómico ou lamentoso — Dukas usa-o para o aprendiz de feiticeiro, Prokofiev para o avô em Pedro e o Lobo." },
  { q: "Qual metal é descrito como o 'elo de ligação' entre metais e madeiras?", opts: ["O trompete", "A trompa (french horn) — o seu timbre pode fundir-se tanto com as madeiras como com os metais", "O trombone", "A tuba"], a: 1, fb: "A trompa tem um timbre único: tocada suavemente (tapada ou em harmónicos), funde-se com madeiras e cordas. Tocada abertamente forte, soa como um metal. Esta versatilidade torna-a a ponte da orquestra. Brahms amava-a particularmente pelas suas linhas líricas e harmonias fundidas." },
  { q: "O trompete é conhecido por:", opts: ["O seu timbre grave e nobre", "O seu esplendor e brilhantismo — cortante no agudo, ideal para fanfarras e melodias heróicas", "A sua suavidade no pianissimo", "O seu carácter cómico"], a: 1, fb: "O trompete é o instrumento das fanfarras, dos chamamentos militares e das linhas heróicas. O seu timbre brilhante em forte é incomparável — mas também pode tocar pianissimo com surdina (som metálico e distante). Usado com parcimónia, marca os momentos-chave." },
  { q: "O trombone é o único metal que pode:", opts: ["Tocar em pizzicato", "Produzir um glissando contínuo — graças à vara que varia o comprimento do tubo", "Tocar 3 partes simultaneamente", "Afinar livremente em tempo real"], a: 1, fb: "A vara do trombone é única nos metais: ao deslizá-la obtém-se um glissando contínuo (portamento), impossível em trompete ou trompa. Esta técnica é usada para efeitos dramáticos (jazz, Stockhausen) e para passagens líricas onde a voz humana parece deslizar de uma nota para outra." },
  { q: "Porque razão a tuba é indispensável na orquestra?", opts: ["Toca a melodia principal", "Funda a harmonia grave dos metais — sem ela, a base dos metais carece de profundidade e de assento", "Substitui o contrabaixo", "É apenas percussiva"], a: 1, fb: "A tuba é o fundamento dos metais: sem ela, os trombones carecem de assento no grave. Frequentemente dobra o contrabaixo ou toca um baixo independente. Composta de numerosos tubos enrolados, é o instrumento mais grave e mais poderoso dos metais." },
  { q: "Porque razão os metais devem frequentemente tocar mais suave do que a sua dinâmica natural?", opts: ["Por convenção musical", "Porque são acusticamente muito mais poderosos do que as cordas e as madeiras — tocar fortissimo cobriria completamente as outras secções", "Porque se cansam rapidamente", "Porque o maestro pede sempre isso"], a: 1, fb: "A acústica dos metais é radicalmente diferente da das cordas. Um único trompetista fortissimo pode cobrir 30 violinistas forte. O orquestrador deve constantemente compensar: 'piano para os metais' em caso de dobramento com as cordas, e reservar o fortissimo para os tutti de grande potência." },
  { q: "Os tímpanos são classificados como instrumentos de som:", opts: ["Indeterminado (como o rullante)", "Determinado — a sua afinação pode ser regulada (geralmente entre Dó2 e Lá3)", "Indefinido conforme a peça", "Apenas rítmico"], a: 1, fb: "Os tímpanos têm uma altura determinada, regulável por pedal: a nota pode ser alterada durante a peça. Uma orquestra usa geralmente 2 a 5 tímpanos cobrindo aproximadamente Dó2–Lá3. Beethoven atribuiu-lhes papéis melódicos e harmónicos precisos (ex. Concerto para violino em Ré menor — tensão em Ré e Lá)." },
  { q: "A caixa aporta principalmente:", opts: ["Sons longos e cantantes", "Uma articulação rítmica cortante — rufos, flams, acentuações militares", "Harmonias graves", "Uma cor suave e intimista"], a: 1, fb: "A caixa é o instrumento da precisão rítmica: rufos rápidos, acentos sincopados, figuras militares. A sua presença marca os momentos de energia e articulação. Ravel usa-a ao longo do Boléro para manter o ritmo ostinato característico." },
  { q: "Qual é a diferença principal entre percussões de som determinado e indeterminado?", opts: ["O tamanho do instrumento", "Os instrumentos de som determinado tocam alturas precisas (tímpanos, xilofone, marimba); os indeterminados trazem timbre e ritmo sem altura fixa (caixa, pratos)", "O material de fabrico", "Não há nenhuma diferença musical"], a: 1, fb: "Distinção fundamental: instrumentos de som determinado (tímpanos, xilofone, vibrafone, marimba, glockenspiel) tocam alturas musicais precisas. Instrumentos de som indeterminado (caixa, bombo, pratos, tam-tam) trazem cor, ritmo e textura." },
  { q: "Qual combinação de dobramento produz o som mais 'fundido' e arredondado?", opts: ["Cordas + Metais", "Cordas + Madeiras — os seus timbres misturam-se naturalmente sem que um domine o outro", "Madeiras + Metais", "Percussões + Cordas"], a: 1, fb: "Cordas + Madeiras formam a combinação de dobramento mais suave. As cordas arredondam o timbre das madeiras; as madeiras precisam a afinação das cordas. É o dobramento preferido nas passagens líricas." },
  { q: "O 'dobramento à oitava' (superoitava) produz que efeito?", opts: ["Nenhuma alteração sonora percetível", "Um aprofundamento (oitava grave) ou clareamento (oitava aguda) do som — sem mudar a cor harmónica", "Uma mudança de tonalidade", "Um acorde dissonante"], a: 1, fb: "O dobramento à oitava enriquece o timbre: adicionar a oitava grave (ex. fagote dobrando o clarinete) traz profundidade e calor; adicionar a oitava aguda (ex. flauta dobrando o violino) traz brilhantismo e projeção. A harmonia não muda — apenas a cor instrumental." },
  { q: "Porque razão evitar dobrar os metais fortissimo sobre as madeiras?", opts: ["Apenas por convenção estilística", "Os metais fortissimo cobrem completamente as madeiras — estas tornam-se inaudíveis", "As madeiras soam melhor sozinhas", "Os metais mudam a tonalidade das madeiras"], a: 1, fb: "A acústica é implacável: um trompetista ou trombonista fortissimo produz um volume sonoro muitas vezes superior a um oboísta ou clarinetista. Em caso de dobramento forte, as madeiras desaparecem sob os metais. A solução: os metais tocam mezzaforte, as madeiras forte." },
  { q: "O dobramento ao uníssono (dois instrumentos, mesma altura) serve para:", opts: ["Mudar a harmonia", "Reforçar a potência e a projeção sem modificar o carácter melódico nem a harmonia", "Criar dissonância", "Transpor uma oitava"], a: 1, fb: "O dobramento ao uníssono soma volumes sem modificar harmonia nem carácter. É usado para reforçar uma linha principal (melodia dobrada ao uníssono por vários instrumentos = projeção máxima), ou para fundir as cores de timbre de dois instrumentos diferentes." },
  { q: "Para uma passagem orquestral lírica e suave, que dobramento é mais apropriado?", opts: ["Trompete + Trombone fortissimo", "Violinos + Flautas ou oboés — cordas + madeiras em dinâmica suave", "Tuba + Bombo", "Metais tutti"], a: 1, fb: "Para uma passagem suave e lírica, cordas + madeiras (flauta, oboé, clarinete) em dinâmica suave é a combinação ideal. Os timbres fundem-se naturalmente, o resultado é arredondado e cantante. Os metais são reservados para os clímax ou usados pianissimo com sordina para uma cor distante." },
  { q: "No Boléro de Ravel, a mesma melodia e harmonia repetem-se 18 vezes para demonstrar:", opts: ["A repetição motívica", "O enriquecimento orquestral progressivo — cada repetição acrescenta instrumentos, ilustrando como a orquestração transforma uma ideia simples", "A forma rondó", "A substituição de trítono"], a: 1, fb: "O Boléro (1928) é o estudo de orquestração mais famoso do repertório: mesma melodia (em Dó maior), mesma harmonia, mesmo ritmo de caixa — apenas a orquestração muda em cada ciclo. Ouvem-se sucessivamente todos os instrumentos da orquestra, depois as suas combinações cada vez mais ricas." },
  { q: "Porque razão o piano raramente é dobrado ao uníssono na orquestra?", opts: ["Por convenção estilística", "Porque o seu timbre percussivo e o seu ataque brusco não se fundem naturalmente com cordas e madeiras", "Porque é demasiado suave", "Porque muda a tonalidade"], a: 1, fb: "O piano tem um timbre percussivo (envelope ataque-decaimento rápido) muito diferente das cordas e madeiras (som contínuo). No dobramento, este contraste cria um choque em vez de uma fusão. Na orquestra, o piano é geralmente usado como solista (concerto), em cor percussiva pontual, ou em papel autónomo." },
  { q: "Qual é o instrumento mais poderoso da orquestra?", opts: ["O bombo", "O trompete (ou os metais em geral) — dominam acusticamente todas as outras famílias em fortissimo", "O violino (porque é o mais numeroso)", "O contrabaixo"], a: 1, fb: "Os metais são os instrumentos mais poderosos da orquestra, e o trompete é frequentemente o mais penetrante. Um único trompetista fortissimo pode cobrir uma secção completa de violinos. Esta potência acústica obriga o orquestrador a tratar os metais com parcimónia." },
  { q: "Como Debussy equilibra as texturas no Prélude à l'après-midi d'un faune?", opts: ["Usando metais fortissimo", "Mantendo os metais muito discretos, favorecendo texturas leves de madeiras e cordas com pedal de harpa", "Usando apenas cordas", "Suprimindo todas as percussões"], a: 1, fb: "O Prélude à l'après-midi d'un faune (1894) é um modelo de orquestração impressionista: flauta solo, harpa, cordas com sordina, madeiras em meias-tintas. Debussy usa os metais muito parcamente para manter a textura transparente — o oposto de Beethoven ou Wagner." },
  { q: "Qual registo corresponde à voz de soprano na orquestra?", opts: ["Violoncelo e fagote", "Violino I, flauta, oboé, trompete — instrumentos de tessitura aguda", "Trompa e viola", "Tuba e contrabaixo"], a: 1, fb: "O registo soprano (voz alta) é coberto por: Violino I (Sol3–Mi6), Flauta (Dó4–Dó7), Oboé (Sib3–Lá6), Trompete (Fá#3–Dó6). Este registo agudo leva a melodia principal na maioria das texturas orquestrais padrão." },
  { q: "Qual registo corresponde à voz de baixo na orquestra?", opts: ["Violino II e clarinete", "Contrabaixo, tuba, fagote grave — instrumentos de tessitura muito grave", "Viola e trompa", "Trombone e oboé"], a: 1, fb: "O registo de baixo é assegurado por: Contrabaixo (Mi1–Sol4, soa 8va mais baixo), Tuba (Sib0–Fá4), Fagote grave (Sib1–Mi3), Contrafagote (Sib0–Mi3). Estes instrumentos fundam a pirâmide harmónica da orquestra — sem eles, o som carece de assento." },
  { q: "Porque razão deve espaçar-se mais as vozes no grave do que no agudo?", opts: ["Apenas por convenção", "Porque no grave, os intervalos estreitos criam lama sonora — os harmónicos confundem-se. No agudo, as terças e segundas soam claras", "Porque os instrumentos graves são maiores", "Porque os harmónicos graves são menos numerosos"], a: 1, fb: "Física acústica fundamental: os harmónicos das notas graves são mais densos e sobrepõem-se mais. Um acorde Dó2–Mi2 (terça menor no grave) soa lodoso; Dó5–Mi5 soa claro. Regra de ouro: quanto mais grave, mais se espaçam as vozes (quintas, oitavas); no agudo, as segundas e terças são aceitáveis." },
  { q: "Um 'buraco harmónico' na orquestração designa:", opts: ["Um silêncio na partitura", "Um registo não coberto por nenhum instrumento — o espetro sonoro tem uma zona vazia, criando um som desequilibrado", "Um acorde diminuto", "Uma modulação falhada"], a: 1, fb: "Um buraco harmónico ocorre quando o registo médio não está coberto enquanto o grave e o agudo estão presentes. O som parece 'oco' — ouve-se o baixo e o soprano mas não o meio. Solução: adicionar instrumentos no registo intermédio (viola, clarinete, trompa, violoncelo médio)." },
  { q: "Na correspondência SATB → orquestra, a voz de tenor (T) é assegurada por:", opts: ["Violino I e flauta", "Violoncelo, trombone, fagote — registo aproximado Dó3–Fá4", "Trompa e viola", "Oboé e clarinete"], a: 1, fb: "A voz de tenor corresponde a: Violoncelo (registo médio Dó3–Mi5), Trombone (Mi2–Fá4, registo tenor principal), Fagote (registo médio Ré3–Mib5). Estes instrumentos asseguram a terceira voz (tenor) nas texturas a 4 partes distribuídas na orquestra." },
  { q: "Para orquestrar um coral a 4 vozes (SATB), a voz de soprano atribui-se a:", opts: ["Tuba e contrabaixo", "Violino I, flauta ou oboé — instrumentos cuja tessitura aguda corresponde à voz soprano", "Fagote e trombone", "Viola e clarinete baixo"], a: 1, fb: "Soprano (voz mais aguda) → Violino I (Sol3–Mi6), Flauta (Dó4–Dó7), Oboé (Sib3–Lá6) ou Trompete. Estes instrumentos têm o brilhantismo e a tessitura para levar a linha melódica principal com clareza e projeção." },
  { q: "Ravel é mais famoso por que obra-prima de orquestração?", opts: ["A Sinfonia n.º 5 em Dó menor", "O Boléro — estudo de orquestração progressiva sobre um ostinato rítmico e uma melodia repetida 18 vezes", "O Requiem", "A Sinfonia Fantástica"], a: 1, fb: "O Boléro (1928) é a composição mais interpretada de Ravel e uma das mais conhecidas do repertório orquestral. Concebido inicialmente como uma encomenda de Ida Rubinstein, tornou-se uma demonstração perfeita da orquestração progressiva: apenas o timbre muda, não a melodia nem a harmonia." },
  { q: "Ravel orquestrou para orquestra uma obra famosa de que compositor?", opts: ["Bach", "Mussorgsky — Quadros de uma Exposição, transcrição do original para piano numa obra-prima orquestral", "Beethoven", "Schubert"], a: 1, fb: "Quadros de uma Exposição (1874) de Mussorgsky era uma suite para piano. Em 1922, Ravel fez uma orquestração considerada uma das mais brilhantes do repertório. Explora cada família de instrumentos para ilustrar cada quadro: o saxofone para 'O Velho Castelo', os trompetes para 'A Grande Porta de Quieve'." },
  { q: "O Prélude à l'après-midi d'un faune de Debussy começa com:", opts: ["Um acorde fortissimo de metais", "Um solo de flauta não acompanhado — melodia cromática, suave e flutuante", "Um ritmo de tímpanos", "Um acorde de cordas pianissimo"], a: 1, fb: "A obra abre com um solo de flauta — melodia cromática (Lá4–Mi4), pianissimo, lenta, evocadora. Este início revolucionário (1894) ilustra a visão impressionista: a cor instrumental (flauta = ar, luz, natureza) está ao serviço da evocação, não do desenvolvimento motívico." },
  { q: "Ravel é considerado um génio da orquestração porque:", opts: ["Compunha mais rápido do que os outros", "Tinha um domínio excecional dos timbres e das combinações instrumentais — cada instrumento no seu registo ideal, cada cor no seu lugar certo", "Usava sempre todos os instrumentos", "Evitava os metais"], a: 1, fb: "Ravel tinha um sentido excecional do 'posicionamento' instrumental — cada instrumento no seu registo de eleição, cada combinação de timbres calculada para o efeito máximo. A sua orquestração dos Quadros é um manual vivo: pode ler-se como usa cada instrumento pela sua cor específica." },
  { q: "Ravel viveu em que época?", opts: ["Barroco (1600–1750)", "Classicismo (1750–1820)", "Romantismo tardio / Impressionismo (1875–1937)", "Contemporâneo (depois de 1950)"], a: 2, fb: "Maurice Ravel (1875–1937) pertence ao período do impressionismo musical (com Debussy, seu contemporâneo). É conhecido pela sua precisão estilística, o seu sentido de humor, as suas obras para piano (Gaspard de la Nuit) e a sua orquestração inigualável (Boléro, La Valse, orquestração dos Quadros de Mussorgsky)." },
  { q: "O pedal de ressonância do piano serve para:", opts: ["Mudar a tonalidade", "Levantar os abafadores — as notas ressoam livremente, sobrepondo-se e criando riqueza harmónica e de ressonância", "Tornar o som mais seco", "Mudar o registo"], a: 1, fb: "O pedal de ressonância (pedal direito) levanta todos os abafadores: as cordas vibram livremente, incluindo as das notas não tocadas (ressonância simpática). Isto cria uma ressonância quente e permite ligar as harmonias. Usado com arte (Chopin, Debussy), enriquece consideravelmente o timbre." },
  { q: "Na escrita pianística padrão, a mão esquerda gere geralmente:", opts: ["Apenas a melodia principal", "O baixo e o acompanhamento harmónico — deixando a mão direita livre para a melodia", "Apenas os ornamentos", "O registo agudo"], a: 1, fb: "A divisão mão direita / mão esquerda no piano é fundamental: mão direita = melodia (registo médio-agudo, aproximadamente Dó4–Dó6); mão esquerda = baixo + acompanhamento (registo Lá0–Dó4). Esta divisão permite a um único músico tocar simultaneamente melodia, harmonia e baixo — um conjunto completo." },
  { q: "Porque razão evitar escrever demasiadas notas no grave do piano?", opts: ["Por convenção de notação", "Porque os harmónicos das notas graves se sobrepõem e criam lama sonora — os acordes estreitos no grave soam difusos", "Porque o registo grave está reservado ao polegar", "Porque as cordas graves são menos numerosas"], a: 1, fb: "No grave (Dó1–Dó3), os harmónicos das notas são numerosos e muito próximos. Acordes estreitos (Dó1–Ré1–Mi1) criam uma lama sonora onde as notas se confundem. Solução: grande espaçamento no grave (oitavas, quintas), acordes mais estreitos no médio-agudo. Chopin e Ravel dominam perfeitamente esta regra." },
  { q: "A formação 'quarteto de cordas' é composta de:", opts: ["4 violinos", "2 violinos, 1 viola, 1 violoncelo — a formação de câmara mais emblemática", "2 violinos, 2 violoncelos", "Violino, viola, violoncelo, contrabaixo"], a: 1, fb: "O quarteto de cordas (2 violinos, viola, violoncelo) é a formação de câmara mais importante do repertório clássico. Cobre um amplo espetro (Sol3–Lá7 acima, Dó2–Sol5 abaixo) com uma homogeneidade de timbre única. Haydn, Mozart, Beethoven e Schubert escreveram as suas páginas mais íntimas para ele." },
  { q: "Um 'trio com piano' (piano trio) é formado de:", opts: ["3 pianos", "Piano, violino, violoncelo — formação de câmara muito frequente no repertório clássico e romântico", "Piano, flauta, clarinete", "Piano, violino, viola"], a: 1, fb: "O trio com piano (piano, violino, violoncelo) é uma das formações de câmara mais frequentes. Beethoven, Schubert, Brahms, Ravel escreveram obras-primas para ele. O equilíbrio é delicado: o piano pode facilmente cobrir o violino e o violoncelo se tocar demasiado forte." },
  { q: "Na música de câmara, o equilíbrio dinâmico entre os músicos é:", opts: ["Gerido por um maestro", "A responsabilidade de cada músico — não há maestro, cada um deve ouvir e adaptar o seu volume", "Fixado pelo compositor com metrónomes", "Não importante — é uma pequena formação"], a: 1, fb: "Na música de câmara não há maestro: o equilíbrio é a responsabilidade coletiva dos músicos. Cada um deve ouvir os outros e adaptar permanentemente o seu volume, a sua fraseação e a sua dinâmica. É uma forma de conversa musical — cada instrumento é simultaneamente narrador e ouvinte." },
];

